/* GlobalVar: radiusIcons */
static const radiusIcons_t *radiusIcons[5] = {((void *)0), ((void *)0), &radiusIcons32px, &radiusIcons40px, ((void *)0)};

/* Function: draw_circle_helper */
static void draw_circle_helper(int x0, int y0, nbgl_radius_t radiusIndex, half_t half, color_t borderColor, color_t innerColor, color_t backgroundColor) {
    const nbgl_icon_details_t *half_icon = ((void *)0);
    nbgl_area_t area = {.bpp = NBGL_BPP_1, .backgroundColor = backgroundColor};
    if (radiusIndex > RADIUS_MAX) {
        return;
    }
    if (borderColor == innerColor) {
        half_icon = pic((void *)radiusIcons[radiusIndex]->leftDisc);
    } else {
        half_icon = pic((void *)radiusIcons[radiusIndex]->leftCircle);
    }
    area.width = half_icon->width;
    area.height = half_icon->height;
    switch (half) {
      case LEFT_HALF:
        area.x0 = x0;
        area.y0 = y0;
        nbgl_frontDrawImage(&area, half_icon->bitmap, 0, borderColor);
        break;
      case RIGHT_HALF:
        area.x0 = x0 - half_icon->width;
        area.y0 = y0;
        nbgl_frontDrawImage(&area, half_icon->bitmap, 2, borderColor);
        break;
    }
}

