/* GlobalVar: radiusValues */
static const uint8_t radiusValues[5] = {20, 28, 32, 40, 44};

/* Function: nbgl_drawRoundedBorderedRect */
void nbgl_drawRoundedBorderedRect(const nbgl_area_t *area, nbgl_radius_t radiusIndex, uint8_t stroke, color_t innerColor, color_t borderColor) {
    uint8_t radius;
    nbgl_area_t rectArea;
    ;
    if (radiusIndex <= RADIUS_MAX) {
        radius = radiusValues[radiusIndex];
    } else if (radiusIndex == RADIUS_0_PIXELS) {
        radius = 0;
    } else {
        ;
        return;
    }
    rectArea.backgroundColor = innerColor;
    rectArea.x0 = area->x0;
    rectArea.y0 = area->y0;
    rectArea.width = area->width;
    rectArea.height = area->height;
    nbgl_frontDrawRect(&rectArea);
    if ((innerColor == borderColor) && (borderColor == area->backgroundColor)) {
        return;
    }
    uint16_t circle_width = 0;
    if (radiusIndex <= RADIUS_MAX) {
        const nbgl_icon_details_t *half_icon = pic((void *)radiusIcons[radiusIndex]->leftDisc);
        circle_width = half_icon->width;
    }
    if ((2 * circle_width) < area->width) {
        if ((area->height - stroke) > 4) {
            rectArea.height = stroke;
            nbgl_frontDrawLine(&rectArea, 1, borderColor);
            rectArea.y0 = area->y0 + area->height - stroke;
            nbgl_frontDrawLine(&rectArea, 1, borderColor);
        } else {
            uint8_t pattern = 0;
            uint32_t i;
            for (i = 0; i < stroke; i++) {
                pattern |= 1 << (7 - i);
            }
            for (i = area->height - stroke; i < area->height; i++) {
                pattern |= 1 << (7 - i);
            }
            memset(ramBuffer, pattern, area->width);
            rectArea.height = 8;
            rectArea.bpp = NBGL_BPP_1;
            nbgl_frontDrawImage(&rectArea, ramBuffer, 0, borderColor);
        }
    }
    if ((2 * radius) < area->height) {
        rectArea.x0 = area->x0;
        rectArea.y0 = area->y0;
        rectArea.width = stroke;
        rectArea.height = area->height;
        rectArea.backgroundColor = area->backgroundColor;
        nbgl_frontDrawLine(&rectArea, 0, borderColor);
        rectArea.x0 = area->x0 + area->width - stroke;
        nbgl_frontDrawLine(&rectArea, 0, borderColor);
    }
    if (radiusIndex <= RADIUS_MAX) {
        draw_circle_helper(area->x0, area->y0, radiusIndex, LEFT_HALF, borderColor, innerColor, area->backgroundColor);
        draw_circle_helper(area->x0 + area->width, area->y0, radiusIndex, RIGHT_HALF, borderColor, innerColor, area->backgroundColor);
    }
}

/* Function: nbgl_drawRoundedRect */
void nbgl_drawRoundedRect(const nbgl_area_t *area, nbgl_radius_t radiusIndex, color_t innerColor) {
    nbgl_area_t rectArea;
    uint8_t radius;
    ;
    if (radiusIndex <= RADIUS_MAX) {
        radius = radiusValues[radiusIndex];
    } else if (radiusIndex == RADIUS_0_PIXELS) {
        radius = 0;
    } else {
        ;
        return;
    }
    rectArea.x0 = area->x0;
    rectArea.y0 = area->y0;
    rectArea.width = area->width;
    rectArea.height = area->height;
    rectArea.backgroundColor = innerColor;
    nbgl_frontDrawRect(&rectArea);
    if (radiusIndex == RADIUS_0_PIXELS) {
        return;
    }
    (void)radius;
    draw_circle_helper(area->x0, area->y0, radiusIndex, LEFT_HALF, innerColor, innerColor, area->backgroundColor);
    draw_circle_helper(area->x0 + area->width, area->y0, radiusIndex, RIGHT_HALF, innerColor, innerColor, area->backgroundColor);
}

/* Function: get_bitmap_byte_cnt */
static uint16_t get_bitmap_byte_cnt(const nbgl_font_t *font, uint8_t charId) {
    if ((charId < font->first_char) || (charId > font->last_char)) {
        return 0;
    }
    uint16_t baseId = charId - font->first_char;
    if (charId < font->last_char) {
        const nbgl_font_character_t *character = (const nbgl_font_character_t *)pic((void *)&font->characters[baseId]);
        const nbgl_font_character_t *nextCharacter = (const nbgl_font_character_t *)pic((void *)&font->characters[baseId + 1]);
        return (nextCharacter->bitmap_offset - character->bitmap_offset);
    } else if (charId == font->last_char) {
        return (font->bitmap_len - font->characters[baseId].bitmap_offset);
    }
    return 0;
}

