/* Function: nbgl_popUnicodeChar */
uint32_t nbgl_popUnicodeChar(const uint8_t **text, uint16_t *textLen, bool *is_unicode) {
    const uint8_t *txt = *text;
    uint8_t cur_char = *txt++;
    uint32_t unicode;
    *is_unicode = 1;
    if ((cur_char >= 240) && (*textLen >= 4)) {
        unicode = (cur_char & 7) << 18;
        unicode |= (*txt++ & 63) << 12;
        unicode |= (*txt++ & 63) << 6;
        unicode |= (*txt++ & 63);
    } else if ((cur_char >= 224) && (*textLen >= 3)) {
        unicode = (cur_char & 15) << 12;
        unicode |= (*txt++ & 63) << 6;
        unicode |= (*txt++ & 63);
    } else if ((cur_char >= 194) && (*textLen >= 2)) {
        unicode = (cur_char & 31) << 6;
        unicode |= (*txt++ & 63);
    } else {
        *is_unicode = 0;
        unicode = cur_char;
    }
    *textLen = *textLen - (txt - *text);
    *text = txt;
    return unicode;
}

