/* Function: getTextWidth */
static uint16_t getTextWidth(nbgl_font_id_e fontId, const char *text, bool breakOnLineEnd, uint16_t maxLen) {
    uint16_t line_width = 0;
    uint16_t max_width = 0;
    const nbgl_font_t *font = nbgl_getFont(fontId);
    uint16_t textLen = ((strlen(text)) < (maxLen) ? (strlen(text)) : (maxLen));
    while (textLen)
        {
            uint8_t char_width;
            uint32_t unicode;
            bool is_unicode;
            unicode = nbgl_popUnicodeChar((const uint8_t **)&text, &textLen, &is_unicode);
            if (unicode == '\n') {
                if (breakOnLineEnd) {
                    break;
                }
                line_width = 0;
                continue;
            } else if (unicode == '\b') {
                if (fontId == BAGL_FONT_OPEN_SANS_REGULAR_11px_1bpp) {
                    fontId = BAGL_FONT_OPEN_SANS_EXTRABOLD_11px_1bpp;
                    font = nbgl_getFont(fontId);
                } else if (fontId == BAGL_FONT_OPEN_SANS_EXTRABOLD_11px_1bpp) {
                    fontId = BAGL_FONT_OPEN_SANS_REGULAR_11px_1bpp;
                    font = nbgl_getFont(fontId);
                }
                continue;
            }
            char_width = getCharWidth(font, unicode, is_unicode);
            line_width += char_width;
            if (line_width > max_width) {
                max_width = line_width;
            }
        }
    return max_width;
}

/* Function: nbgl_getTextWidth */
uint16_t nbgl_getTextWidth(nbgl_font_id_e fontId, const char *text) {
    return getTextWidth(fontId, text, 0, 65535);
}

/* Function: draw_pageIndicator */
static void draw_pageIndicator(nbgl_page_indicator_t *obj, nbgl_obj_t *prevObj, bool computePosition) {
    nbgl_area_t rectArea;
    uint16_t dashWidth;
    if (obj->nbPages < 2) {
        return;
    }
    if (obj->nbPages <= 6) {
        int i;
        obj->obj.area.height = 4;
        if (computePosition) {
            compute_position((nbgl_obj_t *)obj, prevObj);
        }
        ;
        obj->obj.area.backgroundColor = obj->obj.parent->area.backgroundColor;
        dashWidth = (obj->obj.area.width - ((obj->nbPages - 1) * 10)) / obj->nbPages;
        rectArea.x0 = obj->obj.area.x0;
        rectArea.y0 = obj->obj.area.y0;
        rectArea.width = dashWidth;
        rectArea.height = 4;
        rectArea.backgroundColor = obj->obj.area.backgroundColor;
        rectArea.bpp = NBGL_BPP_1;
        for (i = 0; i < obj->activePage; i++) {
            nbgl_frontDrawLine(&rectArea, 0, (obj->style == PROGRESSIVE_INDICATOR) ? BLACK : LIGHT_GRAY);
            rectArea.x0 += dashWidth + 10;
        }
        nbgl_frontDrawLine(&rectArea, 0, BLACK);
        rectArea.x0 += dashWidth + 10;
        i++;
        for (; i < obj->nbPages; i++) {
            nbgl_frontDrawLine(&rectArea, 0, LIGHT_GRAY);
            rectArea.x0 += dashWidth + 10;
        }
    } else {
        char navText[11];
        snprintf(navText, sizeof (navText), "%d of %d", obj->activePage + 1, obj->nbPages);
        obj->obj.area.height = nbgl_getFontHeight(BAGL_FONT_INTER_REGULAR_24px);
        obj->obj.area.width = nbgl_getTextWidth(BAGL_FONT_INTER_REGULAR_24px, navText);
        if (computePosition) {
            compute_position((nbgl_obj_t *)obj, prevObj);
        }
        ;
        obj->obj.area.backgroundColor = obj->obj.parent->area.backgroundColor;
        rectArea.x0 = obj->obj.area.x0;
        rectArea.y0 = obj->obj.area.y0;
        rectArea.width = obj->obj.area.width;
        rectArea.height = obj->obj.area.height;
        rectArea.backgroundColor = obj->obj.area.backgroundColor;
        rectArea.bpp = NBGL_BPP_1;
        nbgl_drawText(&rectArea, navText, strlen(navText), BAGL_FONT_INTER_REGULAR_24px, DARK_GRAY);
    }
}

/* GlobalVar: objRefreshAreaDone */
static bool objRefreshAreaDone;

/* Function: draw_progressBar */
static void draw_progressBar(nbgl_progress_bar_t *obj, nbgl_obj_t *prevObj, bool computePosition) {
    uint8_t stroke = 3;
    if (computePosition) {
        compute_position((nbgl_obj_t *)obj, prevObj);
    }
    ;
    obj->obj.area.backgroundColor = obj->obj.parent->area.backgroundColor;
    if (obj->partialRedraw == 0) {
        if (obj->withBorder) {
            nbgl_drawRoundedBorderedRect((nbgl_area_t *)obj, RADIUS_0_PIXELS, stroke, obj->obj.area.backgroundColor, obj->foregroundColor);
        } else {
            nbgl_drawRoundedRect((nbgl_area_t *)obj, RADIUS_0_PIXELS, obj->obj.area.backgroundColor);
        }
        obj->previousWidth = 0;
    }
    nbgl_area_t barArea;
    uint16_t barWidth = ((obj->state * obj->obj.area.width)) / 100;
    int barDiffWith = barWidth - obj->previousWidth;
    color_t barColor;
    memcpy(&barArea, &obj->obj.area, sizeof(nbgl_area_t));
    if (barDiffWith > 0) {
        barArea.x0 = obj->obj.area.x0 + obj->previousWidth;
        barArea.width = barDiffWith;
        barColor = obj->foregroundColor;
    } else if (barDiffWith < 0) {
        barArea.x0 = obj->obj.area.x0 + obj->previousWidth + barDiffWith;
        barArea.width = -barDiffWith;
        barColor = obj->obj.area.backgroundColor;
    }
    if (barDiffWith != 0) {
        nbgl_drawRoundedRect((nbgl_area_t *)&barArea, RADIUS_0_PIXELS, barColor);
    }
    if (obj->partialRedraw == 1) {
        obj->partialRedraw = 0;
    }
    obj->previousWidth = barWidth;
    extendRefreshArea(&barArea);
    objRefreshAreaDone = 1;
}

