/* Function: nbgl_frontDrawQrInternal */
static void nbgl_frontDrawQrInternal(const nbgl_area_t *area, color_t foregroundColor, nbgl_qrcode_version_t version) {
    int size = qrcodegen_getSize(((QrCodeBuffer_t *)ramBuffer)->qrcode);
    uint16_t idx = 0;
    nbgl_area_t qrArea = {.x0 = area->x0, .y0 = area->y0, .backgroundColor = area->backgroundColor, .bpp = NBGL_BPP_1};
    if (version == QRCODE_V4) {
        qrArea.width = 2;
        qrArea.height = 4 * 2 * size;
        for (int x = 0; x < size; x++) {
            idx = 0;
            for (int y = 0; y < size; y++) {
                ((QrCodeBuffer_t *)ramBuffer)->QrDrawBuffer[idx] = qrcodegen_getModule(((QrCodeBuffer_t *)ramBuffer)->qrcode, x, y) ? 255 : 0;
                ((QrCodeBuffer_t *)ramBuffer)->QrDrawBuffer[idx + 33] = ((QrCodeBuffer_t *)ramBuffer)->QrDrawBuffer[idx];
                idx += 1;
            }
            nbgl_frontDrawImage(&qrArea, ((QrCodeBuffer_t *)ramBuffer)->QrDrawBuffer, 0, foregroundColor);
            qrArea.x0 += 2;
            nbgl_frontDrawImage(&qrArea, ((QrCodeBuffer_t *)ramBuffer)->QrDrawBuffer, 0, foregroundColor);
            qrArea.x0 += 2;
            nbgl_frontDrawImage(&qrArea, ((QrCodeBuffer_t *)ramBuffer)->QrDrawBuffer, 0, foregroundColor);
            qrArea.x0 += 2;
            nbgl_frontDrawImage(&qrArea, ((QrCodeBuffer_t *)ramBuffer)->QrDrawBuffer, 0, foregroundColor);
            qrArea.x0 += 2;
        }
    } else {
        qrArea.width = 1;
        qrArea.height = 4 * size;
        for (int x = 0; x < size; x++) {
            idx = 0;
            memset(((QrCodeBuffer_t *)ramBuffer)->QrDrawBuffer, 0, (size + 1) / 2);
            for (int y = 0; y < size; y++) {
                ((QrCodeBuffer_t *)ramBuffer)->QrDrawBuffer[idx] |= qrcodegen_getModule(((QrCodeBuffer_t *)ramBuffer)->qrcode, x, y) ? 240 >> ((y & 1) * 4) : 0;
                if (y & 1) {
                    idx++;
                }
            }
            nbgl_frontDrawImage(&qrArea, ((QrCodeBuffer_t *)ramBuffer)->QrDrawBuffer, 0, foregroundColor);
            qrArea.x0++;
            nbgl_frontDrawImage(&qrArea, ((QrCodeBuffer_t *)ramBuffer)->QrDrawBuffer, 0, foregroundColor);
            qrArea.x0++;
            nbgl_frontDrawImage(&qrArea, ((QrCodeBuffer_t *)ramBuffer)->QrDrawBuffer, 0, foregroundColor);
            qrArea.x0++;
            nbgl_frontDrawImage(&qrArea, ((QrCodeBuffer_t *)ramBuffer)->QrDrawBuffer, 0, foregroundColor);
            qrArea.x0++;
        }
    }
}

/* Function: calcSegmentBitLength */
static int calcSegmentBitLength(enum qrcodegen_Mode mode, size_t numChars) {
    if (numChars > (unsigned int)32767) {
        return -1;
    }
    long result = (long)numChars;
    if (mode == qrcodegen_Mode_NUMERIC) {
        result = (result * 10 + 2) / 3;
    } else if (mode == qrcodegen_Mode_ALPHANUMERIC) {
        result = (result * 11 + 1) / 2;
    } else if (mode == qrcodegen_Mode_BYTE) {
        result *= 8;
    } else if (mode == qrcodegen_Mode_KANJI) {
        result *= 13;
    } else if (mode == qrcodegen_Mode_ECI && numChars == 0) {
        result = 3 * 8;
    } else {
        if (!(0)) {
            os_sched_exit(-1);
            for (;;)
                ;
        }
        ;
        return -1;
    }
    if (!(result >= 0)) {
        os_sched_exit(-1);
        for (;;)
            ;
    }
    ;
    if (result > 32767) {
        return -1;
    }
    return (int)result;
}

/* Function: qrcodegen_calcSegmentBufferSize */
size_t qrcodegen_calcSegmentBufferSize(enum qrcodegen_Mode mode, size_t numChars) {
    int temp = calcSegmentBitLength(mode, numChars);
    if (temp == -1) {
        return 18446744073709551615UL;
    }
    if (!(0 <= temp && temp <= 32767)) {
        os_sched_exit(-1);
        for (;;)
            ;
    }
    ;
    return ((size_t)temp + 7) / 8;
}

/* Function: getNumRawDataModules */
