/* Function: reedSolomonMultiply */
static uint8_t reedSolomonMultiply(uint8_t x, uint8_t y) {
    uint8_t z = 0;
    for (int i = 7; i >= 0; i--) {
        z = (uint8_t)((z << 1) ^ ((z >> 7) * 285));
        z ^= ((y >> i) & 1) * x;
    }
    return z;
}

/* Function: reedSolomonComputeDivisor */
static void reedSolomonComputeDivisor(int degree, uint8_t result[]) {
    if (!(1 <= degree && degree <= 30)) {
        os_sched_exit(-1);
        for (;;)
            ;
    }
    ;
    memset(result, 0, (size_t)degree * sizeof (result[0]));
    result[degree - 1] = 1;
    uint8_t root = 1;
    for (int i = 0; i < degree; i++) {
        for (int j = 0; j < degree; j++) {
            result[j] = reedSolomonMultiply(result[j], root);
            if (j + 1 < degree) {
                result[j] ^= result[j + 1];
            }
        }
        root = reedSolomonMultiply(root, 2);
    }
}

/* Function: reedSolomonComputeRemainder */
static void reedSolomonComputeRemainder(const uint8_t data[], int dataLen, const uint8_t generator[], int degree, uint8_t result[]) {
    if (!(1 <= degree && degree <= 30)) {
        os_sched_exit(-1);
        for (;;)
            ;
    }
    ;
    memset(result, 0, (size_t)degree * sizeof (result[0]));
    for (int i = 0; i < dataLen; i++) {
        uint8_t factor = data[i] ^ result[0];
        memmove(&result[0], &result[1], (size_t)(degree - 1) * sizeof (result[0]));
        result[degree - 1] = 0;
        for (int j = 0; j < degree; j++) {
            result[j] ^= reedSolomonMultiply(generator[j], factor);
        }
    }
}

/* Function: addEccAndInterleave */
static void addEccAndInterleave(uint8_t data[], int version, enum qrcodegen_Ecc ecl, uint8_t result[]) {
    if (!(0 <= (int)ecl && (int)ecl < 4 && 4 <= version && version <= 10)) {
        os_sched_exit(-1);
        for (;;)
            ;
    }
    ;
    int numBlocks = NUM_ERROR_CORRECTION_BLOCKS[(int)ecl][version];
    int blockEccLen = ECC_CODEWORDS_PER_BLOCK[(int)ecl][version];
    int rawCodewords = getNumRawDataModules(version) / 8;
    int dataLen = getNumDataCodewords(version, ecl);
    int numShortBlocks = numBlocks - rawCodewords % numBlocks;
    int shortBlockDataLen = rawCodewords / numBlocks - blockEccLen;
    uint8_t rsdiv[30];
    reedSolomonComputeDivisor(blockEccLen, rsdiv);
    const uint8_t *dat = data;
    for (int i = 0; i < numBlocks; i++) {
        int datLen = shortBlockDataLen + (i < numShortBlocks ? 0 : 1);
        uint8_t *ecc = &data[dataLen];
        reedSolomonComputeRemainder(dat, datLen, rsdiv, blockEccLen, ecc);
        for (int j = 0, k = i; j < datLen; j++ , k += numBlocks) {
            if (j == shortBlockDataLen) {
                k -= numShortBlocks;
            }
            result[k] = dat[j];
        }
        for (int j = 0, k = dataLen + i; j < blockEccLen; j++ , k += numBlocks) {
            result[k] = ecc[j];
        }
        dat += datLen;
    }
}

/* Function: appendBitsToBuffer */
