/* Function: U4LE_ENCODE */
static inline void U4LE_ENCODE(uint8_t *buf, size_t off, uint32_t value) {
    buf[off + 3] = (value >> 24) & 255;
    buf[off + 2] = (value >> 16) & 255;
    buf[off + 1] = (value >> 8) & 255;
    buf[off + 0] = value & 255;
}

