const ble_profile_info_t BLE_LEDGER_PROFILE_apdu_info = {.type = BLE_LEDGER_PROFILE_APDU, .service_uuid = {.type = 2, .value = {114, 101, 103, 100, 101, 76, 0, 0, 4, 96, 151, 44, 0, 52, 214, 19}}, .init = BLE_LEDGER_PROFILE_apdu_init, .create_db = BLE_LEDGER_PROFILE_apdu_create_db, .handle_in_range = BLE_LEDGER_PROFILE_apdu_handle_in_range, .connection_evt = BLE_LEDGER_PROFILE_apdu_connection_evt, .connection_update_evt = BLE_LEDGER_PROFILE_apdu_connection_update_evt, .encryption_changed = BLE_LEDGER_PROFILE_apdu_encryption_changed, .att_modified = BLE_LEDGER_PROFILE_apdu_att_modified, .write_permit_req = BLE_LEDGER_PROFILE_apdu_write_permit_req, .mtu_changed = BLE_LEDGER_PROFILE_apdu_mtu_changed, .write_rsp_ack = BLE_LEDGER_PROFILE_apdu_write_rsp_ack, .update_char_val_ack = BLE_LEDGER_PROFILE_apdu_update_char_value_ack, .send_packet = BLE_LEDGER_PROFILE_apdu_send_packet, .is_busy = BLE_LEDGER_PROFILE_apdu_is_busy, .data_ready = BLE_LEDGER_PROFILE_apdu_data_ready, .setting = BLE_LEDGER_PROFILE_apdu_setting, .cookie = &ledger_apdu_profile_handle};

/* GlobalVar: ble_ledger_init_data */
static os_io_init_ble_t ble_ledger_init_data;

/* Function: BLE_LEDGER_start */
void BLE_LEDGER_start(void) {
    ;
    if ((ble_ledger_data.state == BLE_STATE_INITIALIZED) || (ble_ledger_data.profiles != ble_ledger_init_data.profile_mask)) {
        ble_ledger_data.cmd_data.hci_cmd_opcode = 65535;
        ble_ledger_data.state = BLE_STATE_STARTING;
        ble_ledger_data.init_step = BLE_INIT_STEP_IDLE;
        ble_ledger_data.nb_of_profile = 0;
        ble_ledger_data.connection.connection_handle = 65535;
        if (ble_ledger_init_data.profile_mask & BLE_LEDGER_PROFILE_APDU) {
            ;
            ble_ledger_data.profile[ble_ledger_data.nb_of_profile++] = (ble_profile_info_t *)pic((void *)&BLE_LEDGER_PROFILE_apdu_info);
        } else if (ble_ledger_init_data.profile_mask & BLE_LEDGER_PROFILE_U2F) {
            ;
        }
        ;
        ble_ledger_data.profiles = ble_ledger_init_data.profile_mask;
        start_mngr(((void *)0), 0);
    } else if (ble_ledger_data.state == BLE_STATE_RUNNING) {
        ble_ledger_data.cmd_data.hci_cmd_opcode = 65535;
        ble_ledger_data.state = BLE_STATE_START_ADVERTISING;
        ble_ledger_data.start_adv_step = BLE_START_ADV_STEP_IDLE;
        start_advertising_mngr(0);
    } else if (ble_ledger_data.state == BLE_STATE_STOPPING) {
        ble_ledger_data.start_after_stop = 1;
    }
}

/* Function: ble_aci_gap_forge_cmd_set_non_discoverable */
void ble_aci_gap_forge_cmd_set_non_discoverable(ble_cmd_data_t *cmd_data) {
    if (!cmd_data) {
        return;
    }
    start_packet_with_opcode(cmd_data, ACI_GAP_SET_NON_DISCOVERABLE_CMD_CODE);
}

/* Function: ble_hci_forge_cmd_disconnect */
void ble_hci_forge_cmd_disconnect(ble_cmd_data_t *cmd_data, uint16_t connection_handle) {
    if (!cmd_data) {
        return;
    }
    start_packet_with_opcode(cmd_data, HCI_DISCONNECT_CMD_CODE);
    U2LE_ENCODE(cmd_data->hci_cmd_buffer, 2, connection_handle);
    cmd_data->hci_cmd_buffer_length = 4;
}

/* Function: stopping_mngr */
static void stopping_mngr(uint16_t opcode) {
    if ((ble_ledger_data.cmd_data.hci_cmd_opcode != 65535) && (opcode != ble_ledger_data.cmd_data.hci_cmd_opcode)) {
        return;
    }
    if (ble_ledger_data.stopping_step == BLE_STOPPING_STEP_IDLE) {
        ;
        ble_ledger_data.stop_after_start = 0;
    }
    if ((ble_ledger_data.stopping_step == BLE_STOPPING_STEP_DISCONNECT - 1) && (ble_ledger_data.connection.connection_handle == 65535)) {
        ble_ledger_data.stopping_step++;
    }
    if ((ble_ledger_data.stopping_step == BLE_STOPPING_STEP_STOP_ADV - 1) && (!ble_ledger_data.advertising_enabled)) {
        ble_ledger_data.stopping_step++;
    }
    ble_ledger_data.stopping_step++;
    switch (ble_ledger_data.stopping_step) {
      case BLE_STOPPING_STEP_DISCONNECT:
        end_pairing_ux(BOLOS_UX_ASYNCHMODAL_PAIRING_STATUS_FAILED);
        ble_hci_forge_cmd_disconnect(&ble_ledger_data.cmd_data, ble_ledger_data.connection.connection_handle);
        send_hci_packet(0);
        break;
      case BLE_STOPPING_STEP_STOP_ADV:
        ble_aci_gap_forge_cmd_set_non_discoverable(&ble_ledger_data.cmd_data);
        send_hci_packet(0);
        break;
      case BLE_STOPPING_STEP_RESET:
        ble_hci_forge_cmd_reset(&ble_ledger_data.cmd_data);
        send_hci_packet(0);
        break;
      case BLE_STOPPING_STEP_END:
        ;
        ble_ledger_data.state = BLE_STATE_INITIALIZED;
        if (ble_ledger_data.start_after_stop) {
            BLE_LEDGER_start();
        }
        break;
      default:
        break;
    }
}

/* Function: BLE_LEDGER_stop */
void BLE_LEDGER_stop(void) {
    ;
    if (ble_ledger_data.state == BLE_STATE_RUNNING) {
        ble_ledger_data.cmd_data.hci_cmd_opcode = 65535;
        ble_ledger_data.state = BLE_STATE_STOPPING;
        ble_ledger_data.stopping_step = BLE_STOPPING_STEP_IDLE;
        stopping_mngr(0);
    } else if ((ble_ledger_data.state == BLE_STATE_STARTING) || (ble_ledger_data.state == BLE_STATE_START_ADVERTISING)) {
        ble_ledger_data.stop_after_start = 1;
    }
}

/* Function: ble_aci_gap_forge_cmd_set_discoverable */
void ble_aci_gap_forge_cmd_set_discoverable(ble_cmd_data_t *cmd_data, ble_cmd_set_discoverable_data_t *data) {
    if ((!cmd_data) || (!data) || (data->local_name_length > 20U)) {
        return;
    }
    start_packet_with_opcode(cmd_data, ACI_GAP_SET_DISCOVERABLE_CMD_CODE);
    cmd_data->hci_cmd_buffer[cmd_data->hci_cmd_buffer_length++] = data->advertising_type;
    U2LE_ENCODE(cmd_data->hci_cmd_buffer, cmd_data->hci_cmd_buffer_length, data->advertising_interval_min);
    cmd_data->hci_cmd_buffer_length += 2;
    U2LE_ENCODE(cmd_data->hci_cmd_buffer, cmd_data->hci_cmd_buffer_length, data->advertising_interval_max);
    cmd_data->hci_cmd_buffer_length += 2;
    cmd_data->hci_cmd_buffer[cmd_data->hci_cmd_buffer_length++] = data->own_address_type;
    cmd_data->hci_cmd_buffer[cmd_data->hci_cmd_buffer_length++] = data->advertising_filter_policy;
    cmd_data->hci_cmd_buffer[cmd_data->hci_cmd_buffer_length++] = data->local_name_length;
    if (data->local_name_length && data->local_name) {
        memcpy(&cmd_data->hci_cmd_buffer[cmd_data->hci_cmd_buffer_length], data->local_name, data->local_name_length);
    }
    cmd_data->hci_cmd_buffer_length += data->local_name_length;
    cmd_data->hci_cmd_buffer[cmd_data->hci_cmd_buffer_length++] = data->service_uuid_length;
    if (data->service_uuid_length && data->service_uuid_list) {
        memcpy(&cmd_data->hci_cmd_buffer[cmd_data->hci_cmd_buffer_length], data->service_uuid_list, data->service_uuid_length);
    }
    cmd_data->hci_cmd_buffer_length += data->service_uuid_length;
    U2LE_ENCODE(cmd_data->hci_cmd_buffer, cmd_data->hci_cmd_buffer_length, data->slave_conn_interval_min);
    cmd_data->hci_cmd_buffer_length += 2;
    U2LE_ENCODE(cmd_data->hci_cmd_buffer, cmd_data->hci_cmd_buffer_length, data->slave_conn_interval_max);
    cmd_data->hci_cmd_buffer_length += 2;
}

/* Function: ble_aci_gap_forge_cmd_update_adv_data */
void ble_aci_gap_forge_cmd_update_adv_data(ble_cmd_data_t *cmd_data, uint8_t adv_data_length, const uint8_t *adv_data) {
    if ((!cmd_data) || (!adv_data) || ((uint16_t)(adv_data_length + 3) > (uint16_t)sizeof (cmd_data->hci_cmd_buffer))) {
        return;
    }
    memset(&cmd_data->hci_cmd_buffer, 0, sizeof (cmd_data->hci_cmd_buffer));
    start_packet_with_opcode(cmd_data, ACI_GAP_UPDATE_ADV_DATA_CMD_CODE);
    cmd_data->hci_cmd_buffer[2] = adv_data_length;
    memcpy(&cmd_data->hci_cmd_buffer[3], adv_data, adv_data_length);
    cmd_data->hci_cmd_buffer_length = 3 + adv_data_length;
}

/* Function: ble_hci_forge_cmd_set_scan_response_data */
void ble_hci_forge_cmd_set_scan_response_data(ble_cmd_data_t *cmd_data, uint8_t scan_response_data_length, const uint8_t *scan_response_data) {
    if ((!cmd_data) || (!scan_response_data) || ((uint16_t)(scan_response_data_length + 3) > (uint16_t)sizeof (cmd_data->hci_cmd_buffer))) {
        return;
    }
    memset(&cmd_data->hci_cmd_buffer, 0, sizeof (cmd_data->hci_cmd_buffer));
    start_packet_with_opcode(cmd_data, HCI_LE_SET_SCAN_RESPONSE_DATA_CMD_CODE);
    cmd_data->hci_cmd_buffer[2] = scan_response_data_length;
    memcpy(&cmd_data->hci_cmd_buffer[3], scan_response_data, scan_response_data_length);
    cmd_data->hci_cmd_buffer_length = ((31U + 3) < (sizeof (cmd_data->hci_cmd_buffer)) ? (31U + 3) : (sizeof (cmd_data->hci_cmd_buffer)));
}

