/* Function: cx_rng_u32 */
static inline uint32_t cx_rng_u32(void) {
    uint32_t r;
    cx_rng_no_throw((uint8_t *)&r, sizeof(uint32_t));
    return r;
}

/* Function: cx_rng_u32_range_func */
uint32_t cx_rng_u32_range_func(uint32_t a, uint32_t b, cx_rng_u32_range_randfunc_t randfunc) {
    uint32_t range = b - a;
    uint32_t r;
    if ((range & (range - 1)) == 0) {
        r = randfunc();
        return a + r % range;
    }
    uint32_t chunk_size = 4294967295U / range;
    uint32_t last_chunk_value = chunk_size * range;
    r = randfunc();
    while (r >= last_chunk_value)
        {
            r = randfunc();
        }
    return a + r / chunk_size;
}

