          case SMP_PAIRING_STATUS_SMP_TIMEOUT:
            ;
            end_pairing_ux(BOLOS_UX_ASYNCHMODAL_PAIRING_STATUS_TIMEOUT);
            break;
          case SMP_PAIRING_STATUS_PAIRING_FAILED:
