                    error_msg[0] = 105;
                    error_msg[1] = 133;
                    USBD_LEDGER_HID_U2F_send_message(pdev, cookie, OS_IO_PACKET_TYPE_USB_U2F_HID_APDU, error_msg, 2, 0);
