            error_msg[1] = CTAP1_ERR_INVALID_LENGTH;
            USBD_LEDGER_HID_U2F_send_message(pdev, cookie, OS_IO_PACKET_TYPE_USB_U2F_HID_CBOR, error_msg, 2, 0);
