/* Function: nbgl_layoutAddUpFooter */
int nbgl_layoutAddUpFooter(nbgl_layout_t *layout, const nbgl_layoutUpFooter_t *upFooterDesc) {
    nbgl_layoutInternal_t *layoutInt = (nbgl_layoutInternal_t *)layout;
    layoutObj_t *obj;
    nbgl_text_area_t *textArea;
    nbgl_line_t *line;
    nbgl_button_t *button;
    ;
    if (layout == ((void *)0)) {
        return -1;
    }
    if ((upFooterDesc == ((void *)0)) || (upFooterDesc->type >= NB_UP_FOOTER_TYPES)) {
        return -2;
    }
    layoutInt->upFooterContainer = (nbgl_container_t *)nbgl_objPoolGet(CONTAINER, layoutInt->layer);
    layoutInt->upFooterContainer->obj.area.width = 400;
    layoutInt->upFooterContainer->layout = VERTICAL;
    layoutInt->upFooterContainer->children = (nbgl_obj_t **)nbgl_containerPoolGet(4, layoutInt->layer);
    layoutInt->upFooterContainer->obj.alignTo = (nbgl_obj_t *)layoutInt->container;
    layoutInt->upFooterContainer->obj.alignment = BOTTOM_MIDDLE;
    switch (upFooterDesc->type) {
      case UP_FOOTER_LONG_PRESS:
        {
            nbgl_progress_bar_t *progressBar;
            obj = layoutAddCallbackObj(layoutInt, (nbgl_obj_t *)layoutInt->upFooterContainer, upFooterDesc->longPress.token, upFooterDesc->longPress.tuneId);
            if (obj == ((void *)0)) {
                return -1;
            }
            layoutInt->upFooterContainer->nbChildren = 4;
            layoutInt->upFooterContainer->obj.area.height = 128;
            layoutInt->upFooterContainer->obj.touchId = LONG_PRESS_BUTTON_ID;
            layoutInt->upFooterContainer->obj.touchMask = ((1 << TOUCHING) | (1 << TOUCH_RELEASED) | (1 << OUT_OF_TOUCH) | (1 << SWIPED_LEFT) | (1 << SWIPED_RIGHT));
            button = (nbgl_button_t *)nbgl_objPoolGet(BUTTON, layoutInt->layer);
            button->obj.alignmentMarginX = 24;
            button->obj.alignment = MID_RIGHT;
            button->innerColor = BLACK;
            button->foregroundColor = WHITE;
            button->borderColor = BLACK;
            button->obj.area.width = (40 * 2);
            button->obj.area.height = (40 * 2);
            button->radius = RADIUS_40_PIXELS;
            button->icon = pic((void *)&C_Check_32px);
            layoutInt->upFooterContainer->children[0] = (nbgl_obj_t *)button;
            textArea = (nbgl_text_area_t *)nbgl_objPoolGet(TEXT_AREA, layoutInt->layer);
            textArea->textColor = BLACK;
            textArea->text = pic((void *)upFooterDesc->longPress.text);
            textArea->textAlignment = MID_LEFT;
            textArea->fontId = BAGL_FONT_INTER_MEDIUM_32px;
            textArea->wrapping = 1;
            textArea->obj.area.width = 400 - 3 * 24 - button->obj.area.width;
            textArea->obj.area.height = nbgl_getTextHeightInWidth(textArea->fontId, textArea->text, textArea->obj.area.width, textArea->wrapping);
            textArea->style = NO_STYLE;
            textArea->obj.alignment = MID_LEFT;
            textArea->obj.alignmentMarginX = 24;
            layoutInt->upFooterContainer->children[1] = (nbgl_obj_t *)textArea;
            line = createHorizontalLine(layoutInt->layer);
            line->obj.alignment = TOP_MIDDLE;
            line->obj.alignmentMarginY = 4 - 1;
            layoutInt->upFooterContainer->children[2] = (nbgl_obj_t *)line;
            progressBar = (nbgl_progress_bar_t *)nbgl_objPoolGet(PROGRESS_BAR, layoutInt->layer);
            progressBar->obj.area.width = 400;
            progressBar->obj.area.height = 8;
            progressBar->obj.alignment = TOP_MIDDLE;
            progressBar->obj.alignmentMarginY = 4;
            progressBar->resetIfOverriden = 1;
            layoutInt->upFooterContainer->children[3] = (nbgl_obj_t *)progressBar;
            break;
        }
      case UP_FOOTER_BUTTON:
        {
            button = (nbgl_button_t *)nbgl_objPoolGet(BUTTON, layoutInt->layer);
            obj = layoutAddCallbackObj(layoutInt, (nbgl_obj_t *)button, upFooterDesc->button.token, upFooterDesc->button.tuneId);
            if (obj == ((void *)0)) {
                return -1;
            }
            layoutInt->upFooterContainer->nbChildren = 1;
            layoutInt->upFooterContainer->obj.area.height = 120;
            button->obj.alignment = CENTER;
            if (upFooterDesc->button.style == BLACK_BACKGROUND) {
                button->innerColor = BLACK;
                button->foregroundColor = WHITE;
            } else {
                button->innerColor = WHITE;
                button->foregroundColor = BLACK;
            }
            if (upFooterDesc->button.style == NO_BORDER) {
                button->borderColor = WHITE;
            } else {
                if (upFooterDesc->button.style == BLACK_BACKGROUND) {
                    button->borderColor = BLACK;
                } else {
                    button->borderColor = LIGHT_GRAY;
                }
            }
            button->text = pic((void *)upFooterDesc->button.text);
            button->fontId = BAGL_FONT_INTER_SEMIBOLD_24px;
            button->icon = pic((void *)upFooterDesc->button.icon);
            button->obj.area.width = (400 - 2 * 24);
            button->obj.area.height = (40 * 2);
            button->radius = RADIUS_40_PIXELS;
            button->obj.alignTo = ((void *)0);
            button->obj.touchMask = (1 << TOUCHED);
            button->obj.touchId = SINGLE_BUTTON_ID;
            layoutInt->upFooterContainer->children[0] = (nbgl_obj_t *)button;
            break;
        }
      case UP_FOOTER_HORIZONTAL_BUTTONS:
        {
            if ((upFooterDesc->horizontalButtons.leftIcon == ((void *)0)) || (upFooterDesc->horizontalButtons.rightText == ((void *)0))) {
                return -1;
            }
            layoutInt->upFooterContainer->nbChildren = 2;
            layoutInt->upFooterContainer->obj.area.height = 120;
            button = (nbgl_button_t *)nbgl_objPoolGet(BUTTON, layoutInt->layer);
            obj = layoutAddCallbackObj(layoutInt, (nbgl_obj_t *)button, upFooterDesc->horizontalButtons.leftToken, upFooterDesc->horizontalButtons.tuneId);
            if (obj == ((void *)0)) {
                return -1;
            }
            obj->index = 1;
            button->obj.alignment = MID_LEFT;
            button->obj.alignmentMarginX = 24;
            button->borderColor = LIGHT_GRAY;
            button->innerColor = WHITE;
            button->foregroundColor = BLACK;
            button->obj.area.width = (40 * 2);
            button->obj.area.height = (40 * 2);
            button->radius = RADIUS_40_PIXELS;
            button->icon = pic((void *)upFooterDesc->horizontalButtons.leftIcon);
            button->fontId = BAGL_FONT_INTER_SEMIBOLD_24px;
            button->obj.touchMask = (1 << TOUCHED);
            button->obj.touchId = CHOICE_2_ID;
            layoutInt->upFooterContainer->children[0] = (nbgl_obj_t *)button;
            button = (nbgl_button_t *)nbgl_objPoolGet(BUTTON, layoutInt->layer);
            obj = layoutAddCallbackObj(layoutInt, (nbgl_obj_t *)button, upFooterDesc->horizontalButtons.rightToken, upFooterDesc->horizontalButtons.tuneId);
            if (obj == ((void *)0)) {
                return -1;
            }
            obj->index = 0;
            button->obj.alignment = MID_RIGHT;
            button->obj.alignmentMarginX = 24;
            button->innerColor = BLACK;
            button->borderColor = BLACK;
            button->foregroundColor = WHITE;
            button->obj.area.width = (400 - 2 * 24) - (40 * 2) - 16;
            button->obj.area.height = (40 * 2);
            button->radius = RADIUS_40_PIXELS;
            button->text = pic((void *)upFooterDesc->horizontalButtons.rightText);
            button->fontId = BAGL_FONT_INTER_SEMIBOLD_24px;
            button->obj.touchMask = (1 << TOUCHED);
            button->obj.touchId = CHOICE_1_ID;
            layoutInt->upFooterContainer->children[1] = (nbgl_obj_t *)button;
            break;
        }
      case UP_FOOTER_TIP_BOX:
        {
            if (upFooterDesc->tipBox.text == ((void *)0)) {
                return -1;
            }
            obj = layoutAddCallbackObj(layoutInt, (nbgl_obj_t *)layoutInt->upFooterContainer, upFooterDesc->tipBox.token, upFooterDesc->tipBox.tuneId);
            if (obj == ((void *)0)) {
                return -1;
            }
            layoutInt->upFooterContainer->nbChildren = 3;
            layoutInt->upFooterContainer->obj.touchId = TIP_BOX_ID;
            layoutInt->upFooterContainer->obj.touchMask = (1 << TOUCHED);
            textArea = (nbgl_text_area_t *)nbgl_objPoolGet(TEXT_AREA, layoutInt->layer);
            textArea->textColor = BLACK;
            textArea->text = pic((void *)upFooterDesc->tipBox.text);
            textArea->textAlignment = MID_LEFT;
            textArea->fontId = BAGL_FONT_INTER_REGULAR_24px;
            textArea->wrapping = 1;
            textArea->obj.area.width = (400 - 2 * 24);
            if (upFooterDesc->tipBox.icon != ((void *)0)) {
                textArea->obj.area.width -= ((nbgl_icon_details_t *)pic((void *)upFooterDesc->tipBox.icon))->width + 24;
            }
            textArea->obj.area.height = nbgl_getTextHeightInWidth(textArea->fontId, textArea->text, textArea->obj.area.width, textArea->wrapping);
            textArea->obj.alignment = MID_LEFT;
            textArea->obj.alignmentMarginX = 24;
            layoutInt->upFooterContainer->children[0] = (nbgl_obj_t *)textArea;
            layoutInt->upFooterContainer->obj.area.height = textArea->obj.area.height;
            line = createHorizontalLine(layoutInt->layer);
            line->obj.alignment = TOP_MIDDLE;
            layoutInt->upFooterContainer->children[1] = (nbgl_obj_t *)line;
            if (upFooterDesc->tipBox.icon != ((void *)0)) {
                nbgl_image_t *image = (nbgl_image_t *)nbgl_objPoolGet(IMAGE, layoutInt->layer);
                image->obj.alignmentMarginX = 24;
                image->obj.alignment = MID_RIGHT;
                image->foregroundColor = BLACK;
                image->buffer = pic((void *)upFooterDesc->tipBox.icon);
                layoutInt->upFooterContainer->children[2] = (nbgl_obj_t *)image;
                if (layoutInt->upFooterContainer->obj.area.height < image->buffer->height) {
                    layoutInt->upFooterContainer->obj.area.height = image->buffer->height;
                }
            }
            layoutInt->upFooterContainer->obj.area.height += 2 * 24;
            break;
        }
      case UP_FOOTER_TEXT:
        {
            obj = layoutAddCallbackObj(layoutInt, (nbgl_obj_t *)layoutInt->upFooterContainer, upFooterDesc->text.token, upFooterDesc->text.tuneId);
            if (obj == ((void *)0)) {
                return -1;
            }
            layoutInt->upFooterContainer->nbChildren = 1;
            layoutInt->upFooterContainer->obj.area.height = 88;
            layoutInt->upFooterContainer->obj.touchId = WHOLE_SCREEN_ID;
            layoutInt->upFooterContainer->obj.touchMask = (1 << TOUCHED);
            if (strlen(pic((void *)upFooterDesc->text.text))) {
                textArea = (nbgl_text_area_t *)nbgl_objPoolGet(TEXT_AREA, layoutInt->layer);
                textArea->textColor = DARK_GRAY;
                textArea->text = pic((void *)upFooterDesc->text.text);
                textArea->textAlignment = CENTER;
                textArea->fontId = BAGL_FONT_INTER_REGULAR_24px;
                textArea->wrapping = 1;
                textArea->obj.area.width = (400 - 2 * 24);
                textArea->obj.area.height = nbgl_getTextHeightInWidth(textArea->fontId, textArea->text, textArea->obj.area.width, textArea->wrapping);
                textArea->obj.alignment = CENTER;
                layoutInt->upFooterContainer->children[0] = (nbgl_obj_t *)textArea;
            }
            break;
        }
      default:
        return -2;
    }
    layoutInt->container->obj.area.height -= layoutInt->upFooterContainer->obj.area.height;
    layoutInt->children[UP_FOOTER_INDEX] = (nbgl_obj_t *)layoutInt->upFooterContainer;
    layoutInt->upFooterType = upFooterDesc->type;
    return layoutInt->upFooterContainer->obj.area.height;
}

/* Function: nbgl_layoutAddButton */
int nbgl_layoutAddButton(nbgl_layout_t *layout, const nbgl_layoutButton_t *buttonInfo) {
    layoutObj_t *obj;
    nbgl_button_t *button;
    nbgl_layoutInternal_t *layoutInt = (nbgl_layoutInternal_t *)layout;
    ;
    if (layout == ((void *)0)) {
        return -1;
    }
    if ((buttonInfo->onBottom) && (!buttonInfo->fittingContent)) {
        if (layoutInt->footerContainer == ((void *)0)) {
            nbgl_layoutFooter_t footerDesc;
            footerDesc.type = FOOTER_SIMPLE_BUTTON;
            footerDesc.separationLine = 0;
            footerDesc.button.text = buttonInfo->text;
            footerDesc.button.token = buttonInfo->token;
            footerDesc.button.tuneId = buttonInfo->tuneId;
            footerDesc.button.icon = buttonInfo->icon;
            footerDesc.button.style = buttonInfo->style;
            return nbgl_layoutAddExtendedFooter(layout, &footerDesc);
        } else {
            nbgl_layoutUpFooter_t upFooterDesc;
            upFooterDesc.type = UP_FOOTER_BUTTON;
            upFooterDesc.button.text = buttonInfo->text;
            upFooterDesc.button.token = buttonInfo->token;
            upFooterDesc.button.tuneId = buttonInfo->tuneId;
            upFooterDesc.button.icon = buttonInfo->icon;
            upFooterDesc.button.style = buttonInfo->style;
            return nbgl_layoutAddUpFooter(layout, &upFooterDesc);
        }
    }
    button = (nbgl_button_t *)nbgl_objPoolGet(BUTTON, layoutInt->layer);
    obj = layoutAddCallbackObj(layoutInt, (nbgl_obj_t *)button, buttonInfo->token, buttonInfo->tuneId);
    if (obj == ((void *)0)) {
        return -1;
    }
    button->obj.alignmentMarginX = 24;
    button->obj.alignmentMarginY = 12;
    button->obj.alignment = NO_ALIGNMENT;
    if (buttonInfo->style == BLACK_BACKGROUND) {
        button->innerColor = BLACK;
        button->foregroundColor = WHITE;
    } else {
        button->innerColor = WHITE;
        button->foregroundColor = BLACK;
    }
    if (buttonInfo->style == NO_BORDER) {
        button->borderColor = WHITE;
    } else {
        if (buttonInfo->style == BLACK_BACKGROUND) {
            button->borderColor = BLACK;
        } else {
            button->borderColor = LIGHT_GRAY;
        }
    }
    button->text = pic((void *)buttonInfo->text);
    button->fontId = BAGL_FONT_INTER_SEMIBOLD_24px;
    button->icon = pic((void *)buttonInfo->icon);
    if (buttonInfo->fittingContent == 1) {
        button->obj.area.width = nbgl_getTextWidth(button->fontId, button->text) + 64 + ((button->icon) ? (button->icon->width + 12) : 0);
        button->obj.area.height = 64;
        button->radius = RADIUS_32_PIXELS;
        if (buttonInfo->onBottom != 1) {
            button->obj.alignmentMarginX += ((400 - 2 * 24) - button->obj.area.width) / 2;
        }
    } else {
        button->obj.area.width = (400 - 2 * 24);
        button->obj.area.height = (40 * 2);
        button->radius = RADIUS_40_PIXELS;
    }
    button->obj.alignTo = ((void *)0);
    button->obj.touchMask = (1 << TOUCHED);
    button->obj.touchId = (buttonInfo->fittingContent) ? EXTRA_BUTTON_ID : SINGLE_BUTTON_ID;
    layoutAddObject(layoutInt, (nbgl_obj_t *)button);
    return 0;
}

/* Function: nbgl_refreshSpecialWithPostRefresh */
void nbgl_refreshSpecialWithPostRefresh(nbgl_refresh_mode_t mode, nbgl_post_refresh_t post_refresh) {
    if ((refreshArea.width == 0) || (refreshArea.height == 0)) {
        return;
    }
    nbgl_frontRefreshArea(&refreshArea, mode, post_refresh);
    ;
    nbgl_refreshReset();
}

/* GlobalVar: gLayout */
static nbgl_layoutInternal_t gLayout[3] = {0};

/* Function: animTickerCallback */
static void animTickerCallback(void) {
    nbgl_image_t *image;
    uint8_t i = 0;
    nbgl_layoutInternal_t *layout;
    if (gLayout[1].nbChildren > 0) {
        layout = &gLayout[1];
    } else {
        layout = &gLayout[0];
    }
    if (layout->animation == ((void *)0)) {
        return;
    }
    while (i < layout->container->nbChildren)
        {
            if (layout->container->children[i]->type == CONTAINER) {
                nbgl_container_t *container = (nbgl_container_t *)layout->container->children[i];
                if (container->children[1]->type == IMAGE) {
                    image = (nbgl_image_t *)container->children[1];
                    if (layout->animation->parsing == LOOP_PARSING) {
                        if (layout->iconIdxInAnim == (layout->animation->nbIcons - 1)) {
                            layout->iconIdxInAnim = 0;
                        } else {
                            layout->iconIdxInAnim++;
                        }
                    } else {
                        if ((layout->incrementAnim) && (layout->iconIdxInAnim >= layout->animation->nbIcons - 1)) {
                            layout->incrementAnim = 0;
                        } else if (layout->iconIdxInAnim == 0) {
                            layout->incrementAnim = 1;
                        }
                        if (layout->incrementAnim) {
                            layout->iconIdxInAnim++;
                        } else {
                            layout->iconIdxInAnim--;
                        }
                    }
                    image->buffer = layout->animation->icons[layout->iconIdxInAnim];
                    nbgl_objDraw((nbgl_obj_t *)image);
                    nbgl_refreshSpecialWithPostRefresh(BLACK_AND_WHITE_FAST_REFRESH, POST_REFRESH_FORCE_POWER_ON);
                    return;
                }
            }
            i++;
        }
}

