/* Function: objIsOfType */
static nbgl_obj_t *objIsOfType(nbgl_obj_t *refObj, nbgl_obj_type_t type) {
    uint8_t i;
    if (refObj->type == type) {
        ;
        return refObj;
    }
    if ((refObj->type == SCREEN) || (refObj->type == CONTAINER)) {
        nbgl_container_t *container = (nbgl_container_t *)refObj;
        if (container->children != ((void *)0)) {
            for (i = 0; i < container->nbChildren; i++) {
                nbgl_obj_t *current = container->children[i];
                if (current != ((void *)0)) {
                    nbgl_obj_t *found = objIsOfType(current, type);
                    if (found) {
                        return found;
                    }
                }
            }
        }
    }
    return ((void *)0);
}

/* Function: nbgl_screenContainsObjType */
nbgl_obj_t *nbgl_screenContainsObjType(nbgl_screen_t *screen, nbgl_obj_type_t type) {
    if (nbScreensOnStack == 0) {
        return ((void *)0);
    }
    return objIsOfType((nbgl_obj_t *)screen, type);
}

/* Function: nbgl_screenSetAt */
static int nbgl_screenSetAt(uint8_t screenIndex, nbgl_obj_t ***children, uint8_t nbChildren, const nbgl_screenTickerConfiguration_t *ticker, nbgl_touchCallback_t callback) {
    if (screenIndex >= 4) {
        ;
        return -1;
    }
    *children = nbgl_containerPoolGet(nbChildren, screenIndex);
    screenStack[screenIndex].container.obj.type = SCREEN;
    screenStack[screenIndex].container.obj.area.backgroundColor = WHITE;
    screenStack[screenIndex].container.obj.area.height = 672;
    screenStack[screenIndex].container.obj.area.width = 400;
    screenStack[screenIndex].container.obj.area.x0 = 0;
    screenStack[screenIndex].container.obj.area.y0 = 0;
    screenStack[screenIndex].container.obj.rel_x0 = 0;
    screenStack[screenIndex].container.obj.rel_y0 = 0;
    screenStack[screenIndex].index = screenIndex;
    screenStack[screenIndex].container.layout = VERTICAL;
    screenStack[screenIndex].container.children = *children;
    screenStack[screenIndex].container.nbChildren = nbChildren;
    screenStack[screenIndex].touchCallback = callback;
    if (ticker != ((void *)0)) {
        screenStack[screenIndex].ticker.tickerCallback = (nbgl_tickerCallback_t)pic((void *)ticker->tickerCallback);
        screenStack[screenIndex].ticker.tickerIntervale = ticker->tickerIntervale;
        screenStack[screenIndex].ticker.tickerValue = ticker->tickerValue;
    } else {
        screenStack[screenIndex].ticker.tickerCallback = ((void *)0);
    }
    screenStack[screenIndex].isUxScreen = (os_sched_current_task() == TASK_BOLOS_UX);
    return 0;
}

/* Function: nbgl_screenPush */
int nbgl_screenPush(nbgl_obj_t ***elements, uint8_t nbElements, const nbgl_screenTickerConfiguration_t *ticker, nbgl_touchCallback_t callback) {
    uint8_t screenIndex;
    if (nbScreensOnStack >= 4) {
        ;
        return -1;
    }
    if (nbScreensOnStack == 0) {
        screenIndex = 1;
        topOfStack = &screenStack[screenIndex];
        topOfStack->next = ((void *)0);
        topOfStack->previous = &screenStack[0];
        screenStack[0].next = topOfStack;
        screenStack[0].container.nbChildren = 0;
        nbScreensOnStack++;
    } else {
        for (screenIndex = 1; screenIndex < 4; screenIndex++) {
            if (screenStack[screenIndex].previous == ((void *)0)) {
                topOfStack->next = &screenStack[screenIndex];
                screenStack[screenIndex].previous = topOfStack;
                nbgl_progress_bar_t *progress = (nbgl_progress_bar_t *)nbgl_screenContainsObjType(topOfStack, PROGRESS_BAR);
                if ((progress != ((void *)0)) && (progress->resetIfOverriden)) {
                    progress->state = 0;
                }
                topOfStack = &screenStack[screenIndex];
                topOfStack->next = ((void *)0);
                break;
            }
        }
        if (screenIndex == 4) {
            ;
        }
    }
    if (nbgl_screenSetAt(screenIndex, elements, nbElements, ticker, callback) >= 0) {
        nbScreensOnStack++;
        ;
        return screenIndex;
    } else {
        return -1;
    }
}

/* Function: nbgl_containerPoolRelease */
void nbgl_containerPoolRelease(uint8_t layer) {
    uint8_t i;
    ;
    if (nbUsedObjsInContainerPool == 0) {
        return;
    }
    for (i = 0; i < 140; i++) {
        if (layer == objPointersPoolLayers[i]) {
            objContainerPool[i] = ((void *)0);
            objPointersPoolLayers[i] = 255;
            nbUsedObjsInContainerPool--;
        }
    }
}

/* Function: nbgl_objPoolRelease */
void nbgl_objPoolRelease(uint8_t layer) {
    uint8_t i;
    ;
    if (nbUsedObjsInPool == 0) {
        return;
    }
    for (i = 0; i < 80; i++) {
        if (layer == objPoolLayers[i]) {
            objPoolLayers[i] = 255;
            nbUsedObjsInPool--;
        }
    }
}

/* Function: nbgl_screenSet */
int nbgl_screenSet(nbgl_obj_t ***elements, uint8_t nbElements, const nbgl_screenTickerConfiguration_t *ticker, nbgl_touchCallback_t callback) {
    if (nbScreensOnStack == 0) {
        nbScreensOnStack++;
        topOfStack = &screenStack[0];
    }
    nbgl_objPoolRelease(0);
    nbgl_containerPoolRelease(0);
    return nbgl_screenSetAt(0, elements, nbElements, ticker, callback);
}

/* Function: getLayoutAndLayoutObj */
static bool getLayoutAndLayoutObj(nbgl_obj_t *obj, nbgl_layoutInternal_t **layout, layoutObj_t **layoutObj) {
    uint8_t i = 3;
    *layout = ((void *)0);
    while (i > 0)
        {
            i--;
            if (gLayout[i].nbChildren > 0) {
                uint8_t j;
                for (j = 0; j < gLayout[i].nbUsedCallbackObjs; j++) {
                    if (obj == gLayout[i].callbackObjPool[j].obj) {
                        ;
                        *layout = &gLayout[i];
                        *layoutObj = &(gLayout[i].callbackObjPool[j]);
                        return 1;
                    }
                }
            }
        }
    return 0;
}

/* Function: layoutNavigationCallback */
bool layoutNavigationCallback(nbgl_obj_t *obj, nbgl_touchType_t eventType, uint8_t nbPages, uint8_t *activePage) {
    if (eventType == TOUCHED) {
        nbgl_container_t *navContainer = (nbgl_container_t *)obj->parent;
        if (obj == navContainer->children[EXIT_BUTTON_INDEX]) {
            *activePage = 255;
            return 1;
        } else if (obj == navContainer->children[PREVIOUS_PAGE_INDEX]) {
            if (*activePage > 0) {
                *activePage = *activePage - 1;
                configButtons(navContainer, nbPages, *activePage);
                return 1;
            }
        } else if (obj == navContainer->children[NEXT_PAGE_INDEX]) {
            if ((nbPages < 2) || (*activePage < (nbPages - 1))) {
                *activePage = *activePage + 1;
                configButtons(navContainer, nbPages, *activePage);
                return 1;
            }
        }
    } else if (eventType == SWIPED_RIGHT) {
        if (*activePage > 0) {
            *activePage = *activePage - 1;
            configButtons((nbgl_container_t *)obj, nbPages, *activePage);
            return 1;
        }
    } else if (eventType == SWIPED_LEFT) {
        if ((nbPages < 2) || (*activePage < (nbPages - 1))) {
            *activePage = *activePage + 1;
            configButtons((nbgl_container_t *)obj, nbPages, *activePage);
            return 1;
        }
    }
    return 0;
}

/* Function: get_hold_to_approve_percent */
static inline uint8_t get_hold_to_approve_percent(uint32_t touch_duration) {
    uint8_t current_step_nb = (touch_duration / (400)) + 1;
    return (current_step_nb * (25));
}

/* Function: nbgl_objIsUx */
bool nbgl_objIsUx(nbgl_obj_t *obj) {
    nbgl_obj_t *parent = obj;
    while (parent->parent != ((void *)0))
        {
            parent = parent->parent;
        }
    if (parent->type == SCREEN) {
        return (((nbgl_screen_t *)parent)->isUxScreen);
    } else {
        return 1;
    }
}

/* Function: nbgl_touchGetTouchDuration */
uint32_t nbgl_touchGetTouchDuration(nbgl_obj_t *obj) {
    nbgl_touchCtx_t *ctx = nbgl_objIsUx(obj) ? &touchCtxs[UX_CTX] : &touchCtxs[APP_CTX];
    if (obj == ctx->lastPressedObj) {
        return (ctx->lastCurrentTime - ctx->lastPressedTime);
    }
    return 0;
}

/* Function: nbgl_wait_pipeline */
__attribute__((weak)) void nbgl_wait_pipeline(void) {
    return;
}

/* Function: longTouchCallback */
static void longTouchCallback(nbgl_obj_t *obj, nbgl_touchType_t eventType, nbgl_layoutInternal_t *layout, layoutObj_t *layoutObj) {
    nbgl_container_t *container = (nbgl_container_t *)obj;
    nbgl_progress_bar_t *progressBar = (nbgl_progress_bar_t *)container->children[3];
    ;
    if (eventType == TOUCHING) {
        uint32_t touchDuration = nbgl_touchGetTouchDuration(obj);
        uint8_t new_state = get_hold_to_approve_percent(touchDuration);
        bool trigger_callback = (new_state >= 100) && (progressBar->state < 100);
        if (new_state >= 100) {
            new_state = 100;
        }
        if (new_state != progressBar->state) {
            progressBar->partialRedraw = 1;
            progressBar->state = new_state;
            nbgl_objDraw((nbgl_obj_t *)progressBar);
            nbgl_refreshSpecialWithPostRefresh(BLACK_AND_WHITE_FAST_REFRESH, POST_REFRESH_FORCE_POWER_ON_WITH_PIPELINE);
        }
        if (trigger_callback) {
            if (layout->callback != ((void *)0)) {
                layout->callback(layoutObj->token, layoutObj->index);
            }
        }
    } else if ((eventType == TOUCH_RELEASED) || (eventType == OUT_OF_TOUCH) || (eventType == SWIPED_LEFT) || (eventType == SWIPED_RIGHT)) {
        nbgl_wait_pipeline();
        progressBar->partialRedraw = 1;
        progressBar->state = 0;
        nbgl_objDraw((nbgl_obj_t *)progressBar);
        nbgl_refreshSpecialWithPostRefresh(BLACK_AND_WHITE_REFRESH, POST_REFRESH_FORCE_POWER_OFF);
    }
}

/* Function: os_io_seph_cmd_piezo_play_tune */
int os_io_seph_cmd_piezo_play_tune(tune_index_e tune_index) {
    int status = 0;
    uint8_t buffer[4];
    if (tune_index >= NB_TUNES) {
        status = -22;
        goto end;
    }
    uint32_t sound_setting = os_setting_get(OS_SETTING_PIEZO_SOUND, ((void *)0), 0);
    if ((!((sound_setting & 2) ? 0 : 1)) && (tune_index < TUNE_TAP_CASUAL)) {
        goto end;
    }
    if ((!((sound_setting & 1) ? 0 : 1)) && (tune_index >= TUNE_TAP_CASUAL)) {
        goto end;
    }
    buffer[0] = (86);
    buffer[1] = 0;
    buffer[2] = 1;
    buffer[3] = (uint8_t)tune_index;
    status = os_io_tx_cmd(OS_IO_PACKET_TYPE_SEPH, buffer, 4, ((void *)0));
  end:
    return status;
}

/* Function: radioTouchCallback */
static void radioTouchCallback(nbgl_obj_t *obj, nbgl_touchType_t eventType, nbgl_layoutInternal_t *layout) {
    uint8_t i = 3, radioIndex = 0, foundRadio = 255, foundRadioIndex;
    if (eventType != TOUCHED) {
        return;
    }
    i = 0;
    while (i < layout->nbUsedCallbackObjs)
        {
            if ((obj == (nbgl_obj_t *)layout->callbackObjPool[i].obj) && (layout->callbackObjPool[i].obj->type == CONTAINER)) {
                nbgl_radio_t *radio = (nbgl_radio_t *)((nbgl_container_t *)layout->callbackObjPool[i].obj)->children[1];
                nbgl_text_area_t *textArea = (nbgl_text_area_t *)((nbgl_container_t *)layout->callbackObjPool[i].obj)->children[0];
                foundRadio = i;
                foundRadioIndex = radioIndex;
                textArea->textColor = BLACK;
                textArea->fontId = BAGL_FONT_INTER_SEMIBOLD_24px;
                radio->state = ON_STATE;
                nbgl_objDraw((nbgl_obj_t *)obj);
            } else if ((layout->callbackObjPool[i].obj->type == CONTAINER) && (((nbgl_container_t *)layout->callbackObjPool[i].obj)->nbChildren == 2) && (((nbgl_container_t *)layout->callbackObjPool[i].obj)->children[1]->type == RADIO_BUTTON)) {
                nbgl_radio_t *radio = (nbgl_radio_t *)((nbgl_container_t *)layout->callbackObjPool[i].obj)->children[1];
                nbgl_text_area_t *textArea = (nbgl_text_area_t *)((nbgl_container_t *)layout->callbackObjPool[i].obj)->children[0];
                radioIndex++;
                if (radio->state == ON_STATE) {
                    radio->state = OFF_STATE;
                    textArea->textColor = DARK_GRAY;
                    textArea->fontId = BAGL_FONT_INTER_REGULAR_24px;
                    nbgl_objDraw((nbgl_obj_t *)layout->callbackObjPool[i].obj);
                }
            }
            i++;
        }
    if (foundRadio != 255) {
        if (layout->callback != ((void *)0)) {
            if (layout->callbackObjPool[foundRadio].tuneId < NB_TUNES) {
                os_io_seph_cmd_piezo_play_tune(layout->callbackObjPool[foundRadio].tuneId);
            }
            nbgl_refreshSpecial(FULL_COLOR_PARTIAL_REFRESH);
            layout->callback(layout->callbackObjPool[foundRadio].token, foundRadioIndex);
        }
    }
}

/* Function: touchCallback */
static void touchCallback(nbgl_obj_t *obj, nbgl_touchType_t eventType) {
    nbgl_layoutInternal_t *layout;
    layoutObj_t *layoutObj;
    bool needRefresh = 0;
    if (obj == ((void *)0)) {
        return;
    }
    ;
    if (getLayoutAndLayoutObj(obj, &layout, &layoutObj) == 0) {
        if (getLayoutAndLayoutObj(obj->parent, &layout, &layoutObj) == 0) {
            ;
            return;
        }
    }
    if (((eventType == SWIPED_UP) || (eventType == SWIPED_DOWN) || (eventType == SWIPED_LEFT) || (eventType == SWIPED_RIGHT)) && (obj->type == CONTAINER)) {
        if (layout->swipeUsage == SWIPE_USAGE_CUSTOM) {
            layoutObj->index = eventType;
        } else if ((layout->swipeUsage == SWIPE_USAGE_NAVIGATION) && ((nbgl_obj_t *)layout->container == obj)) {
            nbgl_container_t *navContainer;
            if (layout->footerType == FOOTER_NAV) {
                navContainer = (nbgl_container_t *)layout->footerContainer;
            } else if (layout->footerType == FOOTER_TEXT_AND_NAV) {
                navContainer = (nbgl_container_t *)layout->footerContainer->children[1];
            } else {
                return;
            }
            if (layoutNavigationCallback((nbgl_obj_t *)navContainer, eventType, layout->nbPages, &layout->activePage) == 0) {
                return;
            }
            layoutObj->index = layout->activePage;
        }
    }
    if (((obj->parent == (nbgl_obj_t *)layout->footerContainer) && (layout->footerType == FOOTER_NAV)) || ((obj->parent->type == CONTAINER) && (obj->parent->parent == (nbgl_obj_t *)layout->footerContainer) && (layout->footerType == FOOTER_TEXT_AND_NAV))) {
        if (layoutNavigationCallback(obj, eventType, layout->nbPages, &layout->activePage) == 0) {
            return;
        }
        layoutObj->index = layout->activePage;
    }
    if ((obj->type == CONTAINER) && (((nbgl_container_t *)obj)->nbChildren >= 2) && (((nbgl_container_t *)obj)->children[1] != ((void *)0)) && (((nbgl_container_t *)obj)->children[1]->type == SWITCH)) {
        nbgl_switch_t *lSwitch = (nbgl_switch_t *)((nbgl_container_t *)obj)->children[1];
        lSwitch->state = (lSwitch->state == ON_STATE) ? OFF_STATE : ON_STATE;
        nbgl_objDraw((nbgl_obj_t *)lSwitch);
        needRefresh = 1;
        layoutObj->index = lSwitch->state;
    } else if ((obj->type == CONTAINER) && (((nbgl_container_t *)obj)->nbChildren == 2) && (((nbgl_container_t *)obj)->children[1] != ((void *)0)) && (((nbgl_container_t *)obj)->children[1]->type == RADIO_BUTTON)) {
        radioTouchCallback(obj, eventType, layout);
        return;
    } else if ((obj->type == CONTAINER) && (((nbgl_container_t *)obj)->nbChildren == 4) && (((nbgl_container_t *)obj)->children[3] != ((void *)0)) && (((nbgl_container_t *)obj)->children[3]->type == PROGRESS_BAR)) {
        longTouchCallback(obj, eventType, layout, layoutObj);
        return;
    }
    ;
    if ((layout->callback != ((void *)0)) && (layoutObj->token != 255)) {
        if (layoutObj->tuneId < NB_TUNES) {
            os_io_seph_cmd_piezo_play_tune(layoutObj->tuneId);
        }
        if (needRefresh) {
            nbgl_refreshSpecial(FULL_COLOR_PARTIAL_REFRESH);
        }
        layout->callback(layoutObj->token, layoutObj->index);
    }
}

/* GlobalVar: nbTouchableControls */
