/* Function: addListItem */
static nbgl_container_t *addListItem(nbgl_layoutInternal_t *layoutInt, const listItem_t *itemDesc) {
    layoutObj_t *obj;
    nbgl_text_area_t *textArea = ((void *)0);
    nbgl_container_t *container;
    color_t color = ((itemDesc->type == TOUCHABLE_BAR_ITEM) && (itemDesc->state == OFF_STATE)) ? LIGHT_GRAY : BLACK;
    nbgl_font_id_e fontId = ((itemDesc->type == TOUCHABLE_BAR_ITEM) && (itemDesc->state == OFF_STATE)) ? BAGL_FONT_INTER_SEMIBOLD_24px : BAGL_FONT_INTER_SEMIBOLD_24px;
    ;
    container = (nbgl_container_t *)nbgl_objPoolGet(CONTAINER, layoutInt->layer);
    obj = layoutAddCallbackObj(layoutInt, (nbgl_obj_t *)container, itemDesc->token, itemDesc->tuneId);
    if (obj == ((void *)0)) {
        return ((void *)0);
    }
    obj->index = itemDesc->index;
    container->children = nbgl_containerPoolGet(4, layoutInt->layer);
    container->nbChildren = 0;
    container->obj.area.width = (400 - 2 * 24);
    container->obj.area.height = 40 + 2 * (itemDesc->large ? 28 : 28);
    container->layout = HORIZONTAL;
    container->obj.alignmentMarginX = 24;
    container->obj.alignment = NO_ALIGNMENT;
    container->obj.alignTo = ((void *)0);
    if (((itemDesc->type == TOUCHABLE_BAR_ITEM) && (itemDesc->state == ON_STATE)) || (itemDesc->type == SWITCH_ITEM)) {
        container->obj.touchMask = (1 << TOUCHED);
        container->obj.touchId = CONTROLS_ID + nbTouchableControls;
        nbTouchableControls++;
    }
    if (itemDesc->text != ((void *)0)) {
        textArea = (nbgl_text_area_t *)nbgl_objPoolGet(TEXT_AREA, layoutInt->layer);
        textArea->textColor = color;
        textArea->text = pic((void *)itemDesc->text);
        textArea->onDrawCallback = ((void *)0);
        textArea->fontId = fontId;
        textArea->wrapping = 1;
        textArea->obj.area.width = container->obj.area.width;
        if (itemDesc->iconLeft != ((void *)0)) {
            textArea->obj.area.width -= ((nbgl_icon_details_t *)pic((void *)itemDesc->iconLeft))->width + 12;
        }
        if (itemDesc->iconRight != ((void *)0)) {
            textArea->obj.area.width -= ((nbgl_icon_details_t *)pic((void *)itemDesc->iconRight))->width + 12;
        } else if (itemDesc->type == SWITCH_ITEM) {
            textArea->obj.area.width -= C_switch_60_40.width + 12;
        }
        textArea->obj.area.height = ((40) > (nbgl_getTextHeightInWidth(textArea->fontId, textArea->text, textArea->obj.area.width, textArea->wrapping)) ? (40) : (nbgl_getTextHeightInWidth(textArea->fontId, textArea->text, textArea->obj.area.width, textArea->wrapping)));
        textArea->style = NO_STYLE;
        textArea->obj.alignment = TOP_LEFT;
        textArea->obj.alignmentMarginY = itemDesc->large ? 28 : 28;
        if (textArea->obj.area.height > 40) {
            textArea->obj.alignmentMarginY -= (textArea->obj.area.height - 40) / 2;
        }
        textArea->textAlignment = MID_LEFT;
        container->children[container->nbChildren] = (nbgl_obj_t *)textArea;
        container->nbChildren++;
    }
    if (itemDesc->iconLeft != ((void *)0)) {
        nbgl_image_t *imageLeft = (nbgl_image_t *)nbgl_objPoolGet(IMAGE, layoutInt->layer);
        imageLeft->foregroundColor = color;
        imageLeft->buffer = pic((void *)itemDesc->iconLeft);
        imageLeft->obj.alignment = MID_LEFT;
        imageLeft->obj.alignTo = (nbgl_obj_t *)textArea;
        imageLeft->obj.alignmentMarginX = 12;
        container->children[container->nbChildren] = (nbgl_obj_t *)imageLeft;
        container->nbChildren++;
        if (textArea != ((void *)0)) {
            textArea->obj.alignmentMarginX = imageLeft->buffer->width + 12;
        }
    }
    if (itemDesc->iconRight != ((void *)0)) {
        nbgl_image_t *imageRight = (nbgl_image_t *)nbgl_objPoolGet(IMAGE, layoutInt->layer);
        imageRight->foregroundColor = color;
        imageRight->buffer = pic((void *)itemDesc->iconRight);
        imageRight->obj.alignment = MID_RIGHT;
        imageRight->obj.alignmentMarginX = 12;
        imageRight->obj.alignTo = (nbgl_obj_t *)textArea;
        container->children[container->nbChildren] = (nbgl_obj_t *)imageRight;
        container->nbChildren++;
    } else if (itemDesc->type == SWITCH_ITEM) {
        nbgl_switch_t *switchObj = (nbgl_switch_t *)nbgl_objPoolGet(SWITCH, layoutInt->layer);
        switchObj->onColor = BLACK;
        switchObj->offColor = LIGHT_GRAY;
        switchObj->state = itemDesc->state;
        switchObj->obj.alignment = MID_RIGHT;
        switchObj->obj.alignmentMarginX = 12;
        switchObj->obj.alignTo = (nbgl_obj_t *)textArea;
        container->children[container->nbChildren] = (nbgl_obj_t *)switchObj;
        container->nbChildren++;
    }
    if (itemDesc->subText != ((void *)0)) {
        nbgl_text_area_t *subTextArea = (nbgl_text_area_t *)nbgl_objPoolGet(TEXT_AREA, layoutInt->layer);
        subTextArea->textColor = color;
        subTextArea->text = pic((void *)itemDesc->subText);
        subTextArea->textAlignment = MID_LEFT;
        subTextArea->fontId = BAGL_FONT_INTER_REGULAR_24px;
        subTextArea->style = NO_STYLE;
        subTextArea->wrapping = 1;
        if (itemDesc->text != ((void *)0)) {
            subTextArea->obj.alignment = BOTTOM_LEFT;
            subTextArea->obj.alignTo = (nbgl_obj_t *)textArea;
            subTextArea->obj.alignmentMarginY = 12;
        } else {
            subTextArea->obj.alignment = TOP_LEFT;
            subTextArea->obj.alignmentMarginY = 24;
            container->obj.area.height = 24;
        }
        if (itemDesc->iconLeft != ((void *)0)) {
            subTextArea->obj.alignmentMarginX = -(((nbgl_icon_details_t *)pic((void *)itemDesc->iconLeft))->width + 12);
        }
        subTextArea->obj.area.width = container->obj.area.width;
        subTextArea->obj.area.height = nbgl_getTextHeightInWidth(subTextArea->fontId, subTextArea->text, subTextArea->obj.area.width, subTextArea->wrapping);
        container->children[container->nbChildren] = (nbgl_obj_t *)subTextArea;
        container->nbChildren++;
        container->obj.area.height += subTextArea->obj.area.height + subTextArea->obj.alignmentMarginY;
    }
    layoutAddObject(layoutInt, (nbgl_obj_t *)container);
    return container;
}

/* Function: nbgl_layoutAddTouchableBar */
int nbgl_layoutAddTouchableBar(nbgl_layout_t *layout, const nbgl_layoutBar_t *barLayout) {
    nbgl_layoutInternal_t *layoutInt = (nbgl_layoutInternal_t *)layout;
    nbgl_container_t *container;
    listItem_t itemDesc = {0};
    ;
    if (layout == ((void *)0)) {
        return -1;
    }
    if (barLayout->text == ((void *)0)) {
        ;
    }
    itemDesc.iconLeft = barLayout->iconLeft;
    itemDesc.iconRight = barLayout->iconRight;
    itemDesc.text = barLayout->text;
    itemDesc.subText = barLayout->subText;
    itemDesc.token = barLayout->token;
    itemDesc.tuneId = barLayout->tuneId;
    itemDesc.state = (barLayout->inactive) ? OFF_STATE : ON_STATE;
    itemDesc.large = barLayout->large;
    itemDesc.type = TOUCHABLE_BAR_ITEM;
    container = addListItem(layoutInt, &itemDesc);
    if (container == ((void *)0)) {
        return -1;
    }
    return container->obj.area.height;
}

