/* Function: displayCustomizedSecurityReport */
static void displayCustomizedSecurityReport(const nbgl_warningDetails_t *details) {
    nbgl_layoutDescription_t layoutDescription = {.modal = 1, .withLeftBorder = 1, .onActionCallback = modalLayoutTouchCallback, .tapActionText = ((void *)0)};
    nbgl_layoutHeader_t headerDesc = {.type = HEADER_BACK_AND_TEXT, .separationLine = 1, .backAndText.icon = ((void *)0), .backAndText.tuneId = TUNE_TAP_CASUAL, .backAndText.token = DISMISS_WARNING_TOKEN};
    uint8_t i;
    sharedContext.reviewWithWarning.modalLayout = nbgl_layoutGet(&layoutDescription);
    headerDesc.backAndText.text = details->title;
    nbgl_layoutAddHeader(sharedContext.reviewWithWarning.modalLayout, &headerDesc);
    if (details->type == BAR_LIST_WARNING) {
        for (i = 0; i < details->barList.nbBars; i++) {
            nbgl_layoutBar_t bar;
            bar.text = details->barList.texts[i];
            bar.subText = details->barList.subTexts[i];
            bar.iconRight = &C_Chevron_32px;
            bar.iconLeft = details->barList.icons[i];
            bar.token = FIRST_WARN_BAR_TOKEN + i;
            bar.tuneId = TUNE_TAP_CASUAL;
            bar.large = 0;
            bar.inactive = 0;
            nbgl_layoutAddTouchableBar(sharedContext.reviewWithWarning.modalLayout, &bar);
            nbgl_layoutAddSeparationLine(sharedContext.reviewWithWarning.modalLayout);
        }
    } else if (details->type == QRCODE_WARNING) {
        nbgl_layoutAddQRCode(sharedContext.reviewWithWarning.modalLayout, &details->qrCode);
        headerDesc.backAndText.text = details->title;
    } else if (details->type == CENTERED_INFO_WARNING) {
        nbgl_layoutAddContentCenter(sharedContext.reviewWithWarning.modalLayout, &details->centeredInfo);
        headerDesc.separationLine = 0;
    }
    nbgl_layoutDraw(sharedContext.reviewWithWarning.modalLayout);
    nbgl_refresh();
}

