/* GlobalVar: securityReportItems */
static const SecurityReportItem_t securityReportItems[5] = {[BLIND_SIGNING_WARN] = {.icon = &C_Warning_32px, .text = "Blind signing required", .subText = "This transaction's details are not fully verifiable. If you sign, you could lose all your assets."}, [W3C_ISSUE_WARN] = {.icon = &C_Warning_32px, .text = "Transaction Check unavailable", .subText = ((void *)0)}, [W3C_RISK_DETECTED_WARN] = {.icon = &C_Warning_32px, .text = "Risk detected", .subText = "This transaction was scanned as risky by Web3 Checks."}, [W3C_THREAT_DETECTED_WARN] = {.icon = &C_Warning_32px, .text = "Critical threat", .subText = "This transaction was scanned as malicious by Web3 Checks."}, [W3C_NO_THREAT_WARN] = {.icon = ((void *)0), .text = "No threat detected", .subText = "Transaction Check didn't find any threat, but always review transaction details carefully."}};

/* GlobalVar: tmpString */
static char tmpString[128];

/* Function: displaySecurityReport */
static void displaySecurityReport(uint32_t set) {
    nbgl_layoutDescription_t layoutDescription = {.modal = 1, .withLeftBorder = 1, .onActionCallback = modalLayoutTouchCallback, .tapActionText = ((void *)0)};
    nbgl_layoutHeader_t headerDesc = {.type = HEADER_BACK_AND_TEXT, .separationLine = 1, .backAndText.icon = ((void *)0), .backAndText.tuneId = TUNE_TAP_CASUAL, .backAndText.token = DISMISS_WARNING_TOKEN};
    nbgl_layoutFooter_t footerDesc = {.type = FOOTER_EMPTY, .separationLine = 0, .emptySpace.height = 0};
    uint8_t i;
    uint8_t nbWarnings = 0;
    const char *provider;
    sharedContext.reviewWithWarning.modalLayout = nbgl_layoutGet(&layoutDescription);
    for (i = 0; i < NB_WARNING_TYPES; i++) {
        if ((set & (1 << i)) && (i != W3C_NO_THREAT_WARN)) {
            nbWarnings++;
        }
    }
    if ((sharedContext.reviewWithWarning.securityReportLevel == 1) && (!sharedContext.reviewWithWarning.isIntro)) {
        for (i = 0; i < NB_WARNING_TYPES; i++) {
            if (sharedContext.reviewWithWarning.warning->predefinedSet & (1 << i)) {
                nbgl_layoutBar_t bar = {0};
                if ((i == BLIND_SIGNING_WARN) || (i == W3C_NO_THREAT_WARN) || (i == W3C_ISSUE_WARN) || (sharedContext.reviewWithWarning.warning->providerMessage == ((void *)0))) {
                    bar.subText = securityReportItems[i].subText;
                } else {
                    bar.subText = sharedContext.reviewWithWarning.warning->providerMessage;
                }
                bar.text = securityReportItems[i].text;
                if (i != W3C_NO_THREAT_WARN) {
                    bar.iconRight = &C_Chevron_32px;
                    bar.token = FIRST_WARN_BAR_TOKEN + i;
                    bar.tuneId = TUNE_TAP_CASUAL;
                } else {
                    bar.token = 255;
                }
                bar.iconLeft = securityReportItems[i].icon;
                nbgl_layoutAddTouchableBar(sharedContext.reviewWithWarning.modalLayout, &bar);
                nbgl_layoutAddSeparationLine(sharedContext.reviewWithWarning.modalLayout);
            }
        }
        headerDesc.backAndText.text = "Security report";
        nbgl_layoutAddHeader(sharedContext.reviewWithWarning.modalLayout, &headerDesc);
        nbgl_layoutDraw(sharedContext.reviewWithWarning.modalLayout);
        nbgl_refresh();
        return;
    }
    if (sharedContext.reviewWithWarning.warning && sharedContext.reviewWithWarning.warning->reportProvider) {
        provider = sharedContext.reviewWithWarning.warning->reportProvider;
    } else {
        provider = "[unknown]";
    }
    if ((set & (1 << W3C_THREAT_DETECTED_WARN)) || (set & (1 << W3C_RISK_DETECTED_WARN))) {
        size_t urlLen = 0;
        char *destStr = tmpString + 128 / 2;
        nbgl_layoutQRCode_t qrCode = {.url = destStr, .text1 = sharedContext.reviewWithWarning.warning->reportUrl, .text2 = "Scan to view full report", .centered = 1, .offsetY = 0};
        snprintf(destStr, 128 / 2, "https://%s", sharedContext.reviewWithWarning.warning->reportUrl);
        urlLen = strlen(destStr) + 1;
        nbgl_layoutAddQRCode(sharedContext.reviewWithWarning.modalLayout, &qrCode);
        footerDesc.emptySpace.height = 24;
        snprintf(destStr + urlLen, 128 / 2 - urlLen, "%s report", provider);
        headerDesc.backAndText.text = destStr + urlLen;
    } else if (set & (1 << BLIND_SIGNING_WARN)) {
        nbgl_contentCenter_t info = {0};
        info.icon = &C_Warning_64px;
        info.title = "This transaction cannot be Clear Signed";
        info.description = "This transaction or message cannot be decoded fully. If you choose to sign, you could be authorizing malicious actions that can drain your wallet.\n\nLearn more: ledger.com/e8";
        nbgl_layoutAddContentCenter(sharedContext.reviewWithWarning.modalLayout, &info);
        footerDesc.emptySpace.height = 32;
        headerDesc.separationLine = 0;
    } else if (set & (1 << W3C_ISSUE_WARN)) {
        nbgl_contentCenter_t info = {0};
        info.icon = &C_Warning_64px;
        info.title = "Transaction Check unavailable";
        info.description = "If you're not using the\nLedger Live app, Transaction Check might not work. If your are using Ledger Live, reject the transaction and try again.\n\nGet help at ledger.com/e11";
        nbgl_layoutAddContentCenter(sharedContext.reviewWithWarning.modalLayout, &info);
        footerDesc.emptySpace.height = 32;
        headerDesc.separationLine = 0;
    }
    nbgl_layoutAddHeader(sharedContext.reviewWithWarning.modalLayout, &headerDesc);
    if (footerDesc.emptySpace.height > 0) {
        nbgl_layoutAddExtendedFooter(sharedContext.reviewWithWarning.modalLayout, &footerDesc);
    }
    nbgl_layoutDraw(sharedContext.reviewWithWarning.modalLayout);
    nbgl_refresh();
}

/* Function: nbgl_screenPop */
int nbgl_screenPop(uint8_t screenIndex) {
    if (nbScreensOnStack == 0) {
        ;
        return -1;
    }
    ;
    nbScreensOnStack--;
    if (&screenStack[screenIndex] == topOfStack) {
        if (nbScreensOnStack == 0) {
            topOfStack = ((void *)0);
        } else {
            topOfStack = topOfStack->previous;
        }
    } else {
        if (screenStack[screenIndex].previous != ((void *)0)) {
            screenStack[screenIndex].previous->next = screenStack[screenIndex].next;
        }
        if (screenStack[screenIndex].next != ((void *)0)) {
            screenStack[screenIndex].next->previous = screenStack[screenIndex].previous;
        }
    }
    screenStack[screenIndex].previous = ((void *)0);
    screenStack[screenIndex].next = ((void *)0);
    screenStack[screenIndex].container.nbChildren = 0;
    screenStack[screenIndex].container.children = ((void *)0);
    nbgl_objPoolRelease(screenIndex);
    nbgl_containerPoolRelease(screenIndex);
    if ((nbScreensOnStack == 1) && (screenStack[0].container.nbChildren == 0)) {
        nbScreensOnStack = 0;
        topOfStack = ((void *)0);
    }
    return 0;
}

