/* GlobalVar: addressConfirmationContext */
static AddressConfirmationContext_t addressConfirmationContext;

/* GlobalVar: genericContext */
static GenericContext_t genericContext;

/* Function: modalLayoutTouchCallback */
static void modalLayoutTouchCallback(int token, uint8_t index) {
    (void)index;
    if (token == DISMISS_QR_TOKEN) {
        nbgl_layoutRelease(addressConfirmationContext.modalLayout);
        addressConfirmationContext.modalLayout = ((void *)0);
        nbgl_screenRedraw();
    } else if (token == DISMISS_WARNING_TOKEN) {
        nbgl_layoutRelease(sharedContext.reviewWithWarning.modalLayout);
        if (sharedContext.reviewWithWarning.securityReportLevel <= 1) {
            sharedContext.reviewWithWarning.modalLayout = ((void *)0);
            nbgl_screenRedraw();
        } else {
            sharedContext.reviewWithWarning.securityReportLevel = 1;
            if (sharedContext.reviewWithWarning.warning->predefinedSet) {
                displaySecurityReport(sharedContext.reviewWithWarning.warning->predefinedSet);
            } else {
                const nbgl_warningDetails_t *details = (sharedContext.reviewWithWarning.isIntro) ? sharedContext.reviewWithWarning.warning->introDetails : sharedContext.reviewWithWarning.warning->reviewDetails;
                displayCustomizedSecurityReport(details);
            }
            return;
        }
    } else if ((token >= FIRST_WARN_BAR_TOKEN) && (token <= LAST_WARN_BAR_TOKEN)) {
        nbgl_layoutRelease(sharedContext.reviewWithWarning.modalLayout);
        sharedContext.reviewWithWarning.securityReportLevel = 2;
        if (sharedContext.reviewWithWarning.warning->predefinedSet) {
            displaySecurityReport(1 << (token - FIRST_WARN_BAR_TOKEN));
        } else {
            const nbgl_warningDetails_t *details = (sharedContext.reviewWithWarning.isIntro) ? sharedContext.reviewWithWarning.warning->introDetails : sharedContext.reviewWithWarning.warning->reviewDetails;
            if (details->type == BAR_LIST_WARNING) {
                displayCustomizedSecurityReport(&details->barList.details[token - FIRST_WARN_BAR_TOKEN]);
            }
        }
        return;
    } else {
        nbgl_layoutRelease(genericContext.modalLayout);
        genericContext.modalLayout = ((void *)0);
        nbgl_screenRedraw();
    }
    nbgl_refresh();
}

/* Function: nbgl_textReduceOnNbLines */
void nbgl_textReduceOnNbLines(nbgl_font_id_e fontId, const char *origText, uint16_t maxWidth, uint8_t nbLines, char *reducedText, uint16_t reducedTextLen) {
    const nbgl_font_t *font = nbgl_getFont(fontId);
    uint16_t textLen = strlen(origText);
    uint16_t width = 0;
    uint8_t currentNbLines = 1;
    uint32_t i = 0, j = 0;
    const uint16_t halfWidth = (maxWidth - nbgl_getTextWidth(fontId, " ... ")) / 2;
    if ((nbLines & 1) == 0) {
        ;
        return;
    }
    while ((i < textLen) && (j < reducedTextLen))
        {
            uint8_t char_width;
            char curChar;
            curChar = origText[i];
            char_width = getCharWidth(font, curChar, 0);
            if (char_width == 0) {
                reducedText[j] = curChar;
                j++;
                i++;
                continue;
            }
            if ((width + char_width) > maxWidth) {
                currentNbLines++;
                width = 0;
                continue;
            } else if ((currentNbLines == ((nbLines / 2) + 1)) && ((width + char_width) > halfWidth)) {
                uint32_t halfFullWidth = (nbLines / 2) * maxWidth + halfWidth;
                uint32_t countDown = textLen;
                reducedText[j - 1] = '.';
                reducedText[j] = '.';
                reducedText[j + 1] = '.';
                width = 0;
                while (width < halfFullWidth)
                    {
                        countDown--;
                        curChar = origText[countDown];
                        char_width = getCharWidth(font, curChar, 0);
                        width += char_width;
                    }
                memcpy(&reducedText[j + 2], &origText[countDown + 1], textLen - countDown + 1);
                return;
            } else {
                reducedText[j] = curChar;
                j++;
                i++;
            }
            width += char_width;
        }
    reducedText[j] = '\x00';
}

/* GlobalVar: reducedAddress */
static char reducedAddress[128];

/* Function: displayAddressQRCode */
static void displayAddressQRCode(void) {
    nbgl_layoutDescription_t layoutDescription = {.modal = 1, .withLeftBorder = 1, .onActionCallback = &modalLayoutTouchCallback, .tapActionText = ((void *)0)};
    nbgl_layoutHeader_t headerDesc = {.type = HEADER_EMPTY, .separationLine = 0, .emptySpace.height = 32};
    nbgl_layoutQRCode_t qrCode = {.url = addressConfirmationContext.tagValuePairs[0].value, .text1 = ((void *)0), .centered = 1, .offsetY = 0};
    addressConfirmationContext.modalLayout = nbgl_layoutGet(&layoutDescription);
    nbgl_layoutAddHeader(addressConfirmationContext.modalLayout, &headerDesc);
    uint16_t nbLines = nbgl_getTextNbLinesInWidth(BAGL_FONT_INTER_REGULAR_24px, addressConfirmationContext.tagValuePairs[0].value, (400 - 2 * 24), 0);
    if (nbLines <= 3) {
        qrCode.text2 = addressConfirmationContext.tagValuePairs[0].value;
    } else {
        nbgl_textReduceOnNbLines(BAGL_FONT_INTER_REGULAR_24px, addressConfirmationContext.tagValuePairs[0].value, (400 - 2 * 24), 3, reducedAddress, 128);
        qrCode.text2 = reducedAddress;
    }
    nbgl_layoutAddQRCode(addressConfirmationContext.modalLayout, &qrCode);
    nbgl_layoutAddFooter(addressConfirmationContext.modalLayout, "Close", DISMISS_QR_TOKEN, TUNE_TAP_CASUAL);
    nbgl_layoutDraw(addressConfirmationContext.modalLayout);
    nbgl_refresh();
}

/* Function: nbgl_getTextMaxLenInNbLines */
bool nbgl_getTextMaxLenInNbLines(nbgl_font_id_e fontId, const char *text, uint16_t maxWidth, uint16_t maxNbLines, uint16_t *len, bool wrapping) {
    const nbgl_font_t *font = nbgl_getFont(fontId);
    uint16_t textLen = strlen(text);
    uint16_t width = 0;
    const char *lastDelimiter = ((void *)0);
    uint32_t lenAtLastDelimiter = 0;
    const char *origText = text;
    const char *previousText;
    while ((textLen) && (maxNbLines > 0))
        {
            uint8_t char_width;
            uint32_t unicode;
            bool is_unicode;
            previousText = text;
            unicode = nbgl_popUnicodeChar((const uint8_t **)&text, &textLen, &is_unicode);
            if ((wrapping == 1) && ((unicode == ' ' || unicode == '\n' || unicode == '\b' || unicode == '\f' || unicode == '-' || unicode == '_'))) {
                lastDelimiter = text;
                lenAtLastDelimiter = textLen;
            }
            if (unicode == '\n') {
                maxNbLines--;
                if (maxNbLines == 0) {
                    text--;
                }
                width = 0;
                continue;
            } else if (unicode == '\f') {
                maxNbLines = 0;
                break;
            } else if (unicode == '\b') {
                if (fontId == BAGL_FONT_OPEN_SANS_REGULAR_11px_1bpp) {
                    fontId = BAGL_FONT_OPEN_SANS_EXTRABOLD_11px_1bpp;
                    font = nbgl_getFont(fontId);
                } else if (fontId == BAGL_FONT_OPEN_SANS_EXTRABOLD_11px_1bpp) {
                    fontId = BAGL_FONT_OPEN_SANS_REGULAR_11px_1bpp;
                    font = nbgl_getFont(fontId);
                }
                continue;
            }
            char_width = getCharWidth(font, unicode, is_unicode);
            if (char_width == 0) {
                continue;
            }
            if ((width + char_width) > maxWidth) {
                if ((wrapping == 1) && (lastDelimiter != ((void *)0))) {
                    text = lastDelimiter;
                    lastDelimiter = ((void *)0);
                    textLen = lenAtLastDelimiter;
                } else {
                    textLen += text - previousText;
                    text = previousText;
                }
                width = 0;
                maxNbLines--;
                continue;
            }
            width += char_width;
        }
    *len = text - origText;
    return (maxNbLines == 0);
}

/* GlobalVar: detailsContext */
static DetailsContext_t detailsContext;

/* Function: getDetailsPageAt */
static const char *getDetailsPageAt(uint8_t detailsPage) {
    uint8_t page = 0;
    const char *currentChar = detailsContext.value;
    while (page < detailsPage)
        {
            uint16_t nbLines = nbgl_getTextNbLinesInWidth(BAGL_FONT_INTER_SEMIBOLD_24px, currentChar, (400 - 2 * 24), 0);
            if (nbLines > 12) {
                uint16_t len;
                nbgl_getTextMaxLenInNbLines(BAGL_FONT_INTER_SEMIBOLD_24px, currentChar, (400 - 2 * 24), 12, &len, detailsContext.wrapping);
                len -= 3;
                currentChar = currentChar + len;
            }
            page++;
        }
    return currentChar;
}

