/* Function: spinnerTickerCallback */
static void spinnerTickerCallback(void) {
    nbgl_spinner_t *spinner;
    uint8_t i = 0;
    nbgl_layoutInternal_t *layout;
    if (gLayout[1].nbChildren > 0) {
        layout = &gLayout[1];
    } else {
        layout = &gLayout[0];
    }
    while (i < layout->container->nbChildren)
        {
            if (layout->container->children[i]->type == CONTAINER) {
                nbgl_container_t *container = (nbgl_container_t *)layout->container->children[i];
                if (container->nbChildren && (container->children[0]->type == SPINNER)) {
                    spinner = (nbgl_spinner_t *)container->children[0];
                    spinner->position++;
                    if (spinner->position == 4) {
                        spinner->position = 0;
                    }
                    nbgl_objDraw((nbgl_obj_t *)spinner);
                    nbgl_refreshSpecial(BLACK_AND_WHITE_FAST_REFRESH);
                    return;
                }
            }
            i++;
        }
}

/* Function: nbgl_layoutAddSpinner */
int nbgl_layoutAddSpinner(nbgl_layout_t *layout, const char *text, const char *subText, uint8_t initPosition) {
    nbgl_layoutInternal_t *layoutInt = (nbgl_layoutInternal_t *)layout;
    nbgl_container_t *container;
    nbgl_text_area_t *textArea;
    nbgl_spinner_t *spinner;
    ;
    if (layout == ((void *)0)) {
        return -1;
    }
    container = (nbgl_container_t *)nbgl_objPoolGet(CONTAINER, layoutInt->layer);
    container->nbChildren = 3;
    container->children = nbgl_containerPoolGet(container->nbChildren, layoutInt->layer);
    container->obj.area.width = (400 - 2 * 24);
    container->layout = VERTICAL;
    container->obj.alignment = CENTER;
    spinner = (nbgl_spinner_t *)nbgl_objPoolGet(SPINNER, layoutInt->layer);
    spinner->position = initPosition;
    spinner->obj.alignment = TOP_MIDDLE;
    container->children[0] = (nbgl_obj_t *)spinner;
    container->obj.area.height += 44;
    textArea = (nbgl_text_area_t *)nbgl_objPoolGet(TEXT_AREA, layoutInt->layer);
    textArea->textColor = BLACK;
    textArea->text = pic((void *)text);
    textArea->textAlignment = CENTER;
    textArea->fontId = (subText != ((void *)0)) ? BAGL_FONT_INTER_MEDIUM_32px : BAGL_FONT_INTER_REGULAR_24px;
    textArea->wrapping = 1;
    textArea->obj.alignmentMarginY = 20;
    textArea->obj.alignTo = (nbgl_obj_t *)spinner;
    textArea->obj.alignment = BOTTOM_MIDDLE;
    textArea->obj.area.width = (400 - 2 * 24);
    textArea->obj.area.height = nbgl_getTextHeightInWidth(textArea->fontId, textArea->text, textArea->obj.area.width, textArea->wrapping);
    textArea->style = NO_STYLE;
    container->obj.area.height += textArea->obj.alignmentMarginY + textArea->obj.area.height;
    container->children[1] = (nbgl_obj_t *)textArea;
    if (subText != ((void *)0)) {
        nbgl_text_area_t *subTextArea;
        subTextArea = (nbgl_text_area_t *)nbgl_objPoolGet(TEXT_AREA, layoutInt->layer);
        subTextArea->textColor = BLACK;
        subTextArea->text = pic((void *)subText);
        subTextArea->textAlignment = CENTER;
        subTextArea->fontId = BAGL_FONT_INTER_REGULAR_24px;
        subTextArea->wrapping = 1;
        subTextArea->obj.alignmentMarginY = 20;
        subTextArea->obj.alignTo = (nbgl_obj_t *)textArea;
        subTextArea->obj.alignment = BOTTOM_MIDDLE;
        subTextArea->obj.area.width = (400 - 2 * 24);
        subTextArea->obj.area.height = nbgl_getTextHeightInWidth(subTextArea->fontId, subTextArea->text, subTextArea->obj.area.width, subTextArea->wrapping);
        subTextArea->style = NO_STYLE;
        container->obj.area.height += subTextArea->obj.alignmentMarginY + subTextArea->obj.area.height;
        container->children[2] = (nbgl_obj_t *)subTextArea;
    }
    layoutAddObject(layoutInt, (nbgl_obj_t *)container);
    if (initPosition != 255) {
        nbgl_screenTickerConfiguration_t tickerCfg;
        tickerCfg.tickerIntervale = 400;
        tickerCfg.tickerValue = 400;
        tickerCfg.tickerCallback = &spinnerTickerCallback;
        nbgl_screenUpdateTicker(layoutInt->layer, &tickerCfg);
    }
    return 0;
}

/* Function: nbgl_layoutUpdateSpinner */
int nbgl_layoutUpdateSpinner(nbgl_layout_t *layout, const char *text, const char *subText, uint8_t position) {
    nbgl_layoutInternal_t *layoutInt = (nbgl_layoutInternal_t *)layout;
    nbgl_container_t *container;
    nbgl_text_area_t *textArea;
    nbgl_spinner_t *spinner;
    int ret = 0;
    ;
    if ((layout == ((void *)0)) || (layoutInt->container->nbChildren == 0)) {
        return -1;
    }
    container = (nbgl_container_t *)layoutInt->container->children[0];
    if ((container->obj.type != CONTAINER) || (container->nbChildren < 2)) {
        return -1;
    }
    spinner = (nbgl_spinner_t *)container->children[0];
    if (spinner->obj.type != SPINNER) {
        return -1;
    }
    if (spinner->position != position) {
        spinner->position = position;
        nbgl_objDraw((nbgl_obj_t *)spinner);
        ret = 1;
    }
    textArea = (nbgl_text_area_t *)container->children[1];
    if (textArea->obj.type != TEXT_AREA) {
        return -1;
    }
    const char *newText = pic((void *)text);
    size_t newTextLen = strlen(newText);
    if ((newTextLen != strlen(textArea->text)) || memcmp(textArea->text, newText, newTextLen)) {
        textArea->text = newText;
        nbgl_objDraw((nbgl_obj_t *)textArea);
        ret = 2;
    }
    if (subText != ((void *)0)) {
        nbgl_text_area_t *subTextArea;
        if (container->nbChildren != 3) {
            return -1;
        }
        subTextArea = (nbgl_text_area_t *)container->children[2];
        if (subTextArea->obj.type != TEXT_AREA) {
            return -1;
        }
        const char *newSubText = pic((void *)subText);
        size_t newSubTextLen = strlen(newSubText);
        if ((newSubTextLen != strlen(subTextArea->text)) || memcmp(subTextArea->text, newSubText, newSubTextLen)) {
            subTextArea->text = newSubText;
            nbgl_objDraw((nbgl_obj_t *)subTextArea);
            ret = 2;
        }
    }
    return ret;
}

/* Function: nbgl_useCaseSpinner */
void nbgl_useCaseSpinner(const char *text) {
    if (genericContext.type != USE_CASE_SPINNER) {
        memset(&genericContext, 0, sizeof (genericContext));
        genericContext.type = USE_CASE_SPINNER;
        nbgl_layoutDescription_t layoutDescription = {0};
        layoutDescription.withLeftBorder = 1;
        genericContext.backgroundLayout = nbgl_layoutGet(&layoutDescription);
        nbgl_layoutAddSpinner(genericContext.backgroundLayout, text, ((void *)0), genericContext.spinnerPosition);
        nbgl_layoutDraw(genericContext.backgroundLayout);
        nbgl_refreshSpecial(FULL_COLOR_PARTIAL_REFRESH);
    } else {
        genericContext.spinnerPosition++;
        if (genericContext.spinnerPosition == 4) {
            genericContext.spinnerPosition = 0;
        }
        int ret = nbgl_layoutUpdateSpinner(genericContext.backgroundLayout, text, ((void *)0), genericContext.spinnerPosition);
        if (ret == 1) {
            nbgl_refreshSpecial(BLACK_AND_WHITE_FAST_REFRESH);
        } else if (ret == 2) {
            nbgl_refreshSpecial(FULL_COLOR_PARTIAL_REFRESH);
        }
    }
}

