/* Function: bundleNavReviewStreamingChoice */
static void bundleNavReviewStreamingChoice(bool confirm) {
    if (confirm) {
        if (localContentsList[0].type != INFO_LONG_PRESS) {
            nbgl_useCaseSpinner("Processing");
        }
        bundleNavContext.reviewStreaming.choiceCallback(1);
    } else {
        bundleNavReviewAskRejectionConfirmation(bundleNavContext.reviewStreaming.operationType, bundleNavReviewStreamingConfirmRejection);
    }
}

/* GlobalVar: genericContextPagesInfo */
static uint8_t genericContextPagesInfo[128];

/* Function: genericContextGetPageInfo */
static void genericContextGetPageInfo(uint8_t pageIdx, uint8_t *nbElements, bool *flag) {
    uint8_t pageData = genericContextPagesInfo[pageIdx / (8 / (3 + 1))] >> ((pageIdx % (8 / (3 + 1))) * (3 + 1));
    if (nbElements != ((void *)0)) {
        *nbElements = ((pageData) & 7);
    }
    if (flag != ((void *)0)) {
        *flag = (((pageData) & 8) >> 3);
    }
}

/* Function: getContentAtIdx */
static const nbgl_content_t *getContentAtIdx(const nbgl_genericContents_t *genericContents, int8_t contentIdx, nbgl_content_t *content) {
    if (contentIdx < 0 || contentIdx >= genericContents->nbContents) {
        ;
        return ((void *)0);
    }
    if (genericContents->callbackCallNeeded) {
        memset(content, 0, sizeof(nbgl_content_t));
        genericContents->contentGetterCallback(contentIdx, content);
        return content;
    } else {
        return pic((void *)&genericContents->contentsList[contentIdx]);
    }
}

/* Function: getContentNbElement */
static uint8_t getContentNbElement(const nbgl_content_t *content) {
    switch (content->type) {
      case TAG_VALUE_LIST:
        return content->content.tagValueList.nbPairs;
      case TAG_VALUE_CONFIRM:
        return content->content.tagValueConfirm.tagValueList.nbPairs;
      case SWITCHES_LIST:
        return content->content.switchesList.nbSwitches;
      case INFOS_LIST:
        return content->content.infosList.nbInfos;
      case CHOICES_LIST:
        return content->content.choicesList.nbChoices;
      case BARS_LIST:
        return content->content.barsList.nbBars;
      default:
        return 1;
    }
}

/* GlobalVar: navInfo */
static nbgl_pageNavigationInfo_t navInfo;

/* GlobalVar: onContentAction */
static nbgl_contentActionCallback_t onContentAction;

/* Function: genericContextComputeNextPageParams */
static const nbgl_content_t *genericContextComputeNextPageParams(uint8_t pageIdx, nbgl_content_t *content, uint8_t *p_nbElementsInNextPage, bool *p_flag) {
    int8_t nextContentIdx = genericContext.currentContentIdx;
    int16_t nextElementIdx = genericContext.currentElementIdx;
    uint8_t nbElementsInNextPage;
    genericContextGetPageInfo(pageIdx, &nbElementsInNextPage, p_flag);
    *p_nbElementsInNextPage = nbElementsInNextPage;
    if (pageIdx > navInfo.activePage) {
        uint8_t nbElementsInCurrentPage;
        genericContextGetPageInfo(navInfo.activePage, &nbElementsInCurrentPage, ((void *)0));
        nextElementIdx += nbElementsInCurrentPage;
        if ((nextElementIdx >= genericContext.currentContentElementNb) && (genericContext.currentContentElementNb > 0)) {
            nextContentIdx += 1;
            nextElementIdx = 0;
        }
    }
    if (pageIdx < navInfo.activePage) {
        nextElementIdx -= nbElementsInNextPage;
        if (nextElementIdx < 0) {
            nextContentIdx -= 1;
            nextElementIdx = -nbElementsInNextPage;
        }
    }
    const nbgl_content_t *p_content;
    if ((nextContentIdx == -1) && (genericContext.hasStartingContent)) {
        p_content = &localContentsList[0];
    } else if ((nextContentIdx == genericContext.genericContents.nbContents) && (genericContext.hasFinishingContent)) {
        p_content = &localContentsList[1];
    } else {
        p_content = getContentAtIdx(&genericContext.genericContents, nextContentIdx, content);
        if (p_content == ((void *)0)) {
            ;
            return ((void *)0);
        }
    }
    if ((nextContentIdx != genericContext.currentContentIdx) || (genericContext.currentContentElementNb == 0)) {
        genericContext.currentContentIdx = nextContentIdx;
        genericContext.currentContentElementNb = getContentNbElement(p_content);
        onContentAction = pic((void *)p_content->contentActionCallback);
        if (nextElementIdx < 0) {
            nextElementIdx = genericContext.currentContentElementNb + nextElementIdx;
        }
    }
    if ((nextElementIdx < 0) || (nextElementIdx >= genericContext.currentContentElementNb)) {
        ;
        return ((void *)0);
    }
    genericContext.currentElementIdx = nextElementIdx;
    navInfo.activePage = pageIdx;
    return p_content;
}

