/* GlobalVar: onAction */
static nbgl_callback_t onAction;

/* GlobalVar: onChoice */
static nbgl_choiceCallback_t onChoice;

/* GlobalVar: onContinue */
static nbgl_callback_t onContinue;

/* GlobalVar: onControls */
static nbgl_layoutTouchCallback_t onControls;

/* GlobalVar: onQuit */
static nbgl_callback_t onQuit;

/* Function: pageCallback */
static void pageCallback(int token, uint8_t index) {
    ;
    if (token == QUIT_TOKEN) {
        if (onQuit != ((void *)0)) {
            onQuit();
        }
    } else if (token == CONTINUE_TOKEN) {
        if (onContinue != ((void *)0)) {
            onContinue();
        }
    } else if (token == CHOICE_TOKEN) {
        if (onChoice != ((void *)0)) {
            onChoice((index == 0) ? 1 : 0);
        }
    } else if (token == ACTION_BUTTON_TOKEN) {
        if ((index == 0) && (onAction != ((void *)0))) {
            onAction();
        } else if ((index == 1) && (onQuit != ((void *)0))) {
            onQuit();
        }
    } else if (token == ADDRESS_QRCODE_BUTTON_TOKEN) {
        displayAddressQRCode();
    } else if (token == CONFIRM_TOKEN) {
        if (onChoice != ((void *)0)) {
            onChoice(1);
        }
    } else if (token == REJECT_TOKEN) {
        if (onChoice != ((void *)0)) {
            onChoice(0);
        }
    } else if (token == DETAILS_BUTTON_TOKEN) {
        displayDetails(genericContext.detailsItem, genericContext.detailsvalue, genericContext.detailsWrapping);
    } else if (token == NAV_TOKEN) {
        if (index == 255) {
            if (onQuit != ((void *)0)) {
                onQuit();
            }
        } else {
            if (navType == GENERIC_NAV || navType == STREAMING_NAV) {
                displayGenericContextPage(index, 0);
            } else if (navType == REVIEW_NAV) {
                displayReviewPage(index, 0);
            } else {
                displaySettingsPage(index, 0);
            }
        }
    } else if (token == NEXT_TOKEN) {
        if (onNav != ((void *)0)) {
            displayReviewPage(navInfo.activePage + 1, 0);
        } else {
            displayGenericContextPage(navInfo.activePage + 1, 0);
        }
    } else if (token == BACK_TOKEN) {
        if (onNav != ((void *)0)) {
            displayReviewPage(navInfo.activePage - 1, 1);
        } else {
            displayGenericContextPage(navInfo.activePage - 1, 0);
        }
    } else if (token == SKIP_TOKEN) {
        displaySkipWarning();
    } else if (token == VALUE_ALIAS_TOKEN) {
        const nbgl_contentTagValue_t *pair;
        if (genericContext.currentPairs != ((void *)0)) {
            pair = &genericContext.currentPairs[genericContext.currentElementIdx + index];
        } else {
            pair = genericContext.currentCallback(genericContext.currentElementIdx + index);
        }
        displayFullValuePage(pair->item, pair->value, pair->extension);
    } else if (token == BLIND_WARNING_TOKEN) {
        sharedContext.reviewWithWarning.isIntro = 0;
        sharedContext.reviewWithWarning.warning = ((void *)0);
        displaySecurityReport(1 << BLIND_SIGNING_WARN);
    } else if (token == WARNING_BUTTON_TOKEN) {
        sharedContext.reviewWithWarning.securityReportLevel = 1;
        if (sharedContext.reviewWithWarning.warning->predefinedSet) {
            displaySecurityReport(sharedContext.reviewWithWarning.warning->predefinedSet);
        } else {
            if (sharedContext.reviewWithWarning.isIntro) {
                displayCustomizedSecurityReport(sharedContext.reviewWithWarning.warning->introDetails);
            } else {
                displayCustomizedSecurityReport(sharedContext.reviewWithWarning.warning->reviewDetails);
            }
        }
    } else if (token == TIP_BOX_TOKEN) {
        if (genericContext.validWarningCtx && (sharedContext.reviewWithWarning.warning->predefinedSet != 0)) {
            sharedContext.reviewWithWarning.securityReportLevel = 1;
            displaySecurityReport(sharedContext.reviewWithWarning.warning->predefinedSet);
        } else {
            displayInfosListModal(activeTipBox.modalTitle, &activeTipBox.infos, 0);
        }
    } else {
        if (onContentAction != ((void *)0)) {
            onContentAction(token, index, navInfo.activePage);
        }
        if (onControls != ((void *)0)) {
            onControls(token, index);
        }
    }
}

/* Function: reset_callbacks */
static void reset_callbacks(void) {
    onQuit = ((void *)0);
    onContinue = ((void *)0);
    onAction = ((void *)0);
    onNav = ((void *)0);
    onControls = ((void *)0);
    onContentAction = ((void *)0);
    onChoice = ((void *)0);
    onModalConfirm = ((void *)0);
}

/* Function: tickerCallback */
static void tickerCallback(void) {
    nbgl_pageRelease(pageContext);
    if (onQuit != ((void *)0)) {
        onQuit();
    }
}

