/* Function: getNbTagValuesInPage */
static uint8_t getNbTagValuesInPage(uint8_t nbPairs, const nbgl_contentTagValueList_t *tagValueList, uint8_t startIndex, bool isSkippable, bool hasConfirmationButton, bool hasDetailsButton, bool *requireSpecificDisplay) {
    uint8_t nbPairsInPage = 0;
    uint16_t currentHeight = 24;
    uint16_t maxUsableHeight = (672 - 32 - 92);
    if (isSkippable) {
        maxUsableHeight -= 88 - 32;
    }
    *requireSpecificDisplay = 0;
    while (nbPairsInPage < nbPairs)
        {
            const nbgl_layoutTagValue_t *pair;
            nbgl_font_id_e value_font;
            uint16_t nbLines;
            if (nbPairsInPage > 0) {
                currentHeight += 12;
            }
            if (tagValueList->pairs != ((void *)0)) {
                pair = pic((void *)&tagValueList->pairs[startIndex + nbPairsInPage]);
            } else {
                pair = pic((void *)tagValueList->callback(startIndex + nbPairsInPage));
            }
            if (pair->forcePageStart && nbPairsInPage > 0) {
                break;
            }
            if (pair->centeredInfo) {
                if (nbPairsInPage > 0) {
                    break;
                } else {
                    nbPairsInPage = 1;
                    *requireSpecificDisplay = 1;
                    break;
                }
            }
            currentHeight += nbgl_getTextHeightInWidth(BAGL_FONT_INTER_REGULAR_24px, pair->item, (400 - 2 * 24), tagValueList->wrapping);
            currentHeight += 4;
            if (tagValueList->smallCaseForValue) {
                value_font = BAGL_FONT_INTER_REGULAR_24px;
            } else {
                value_font = BAGL_FONT_INTER_MEDIUM_32px;
            }
            currentHeight += nbgl_getTextHeightInWidth(value_font, pair->value, (400 - 2 * 24), tagValueList->wrapping);
            nbLines = nbgl_getTextNbLinesInWidth(value_font, pair->value, (400 - 2 * 24), tagValueList->wrapping);
            if ((currentHeight >= maxUsableHeight) || (nbLines > 10)) {
                if (nbPairsInPage == 0) {
                    nbPairsInPage = 1;
                    *requireSpecificDisplay = 1;
                }
                break;
            }
            nbPairsInPage++;
        }
    if (hasConfirmationButton && (nbPairsInPage == nbPairs)) {
        maxUsableHeight -= 120;
        if (currentHeight > maxUsableHeight) {
            nbPairsInPage--;
        }
    } else if (hasDetailsButton) {
        maxUsableHeight -= (32 * 2);
        if (currentHeight > maxUsableHeight) {
            nbPairsInPage--;
        }
    }
    return nbPairsInPage;
}

