/* GlobalVar: nbMaxElementsPerContentType */
static const uint8_t nbMaxElementsPerContentType[] = {1, 1, 1, 1, 1, 1, 1, 3, 3, 5, 5};

/* Function: getNbPagesForContent */
static uint8_t getNbPagesForContent(const nbgl_content_t *content, uint8_t pageIdxStart, bool isLast, bool isSkippable) {
    uint8_t nbElements = 0;
    uint8_t nbPages = 0;
    uint8_t nbElementsInPage;
    uint8_t elemIdx = 0;
    bool flag;
    nbElements = getContentNbElement(content);
    while (nbElements > 0)
        {
            flag = 0;
            bool hasNav = !isLast || (pageIdxStart > 0) || (elemIdx > 0);
            if (content->type == TAG_VALUE_LIST) {
                nbElementsInPage = getNbTagValuesInPage(nbElements, &content->content.tagValueList, elemIdx, isSkippable, 0, 0, &flag);
            } else if (content->type == TAG_VALUE_CONFIRM) {
                nbElementsInPage = getNbTagValuesInPage(nbElements, &content->content.tagValueConfirm.tagValueList, elemIdx, isSkippable, isLast, !isLast, &flag);
            } else if (content->type == INFOS_LIST) {
                nbElementsInPage = nbgl_useCaseGetNbInfosInPage(nbElements, &content->content.infosList, elemIdx, hasNav);
            } else if (content->type == SWITCHES_LIST) {
                nbElementsInPage = nbgl_useCaseGetNbSwitchesInPage(nbElements, &content->content.switchesList, elemIdx, hasNav);
            } else if (content->type == BARS_LIST) {
                nbElementsInPage = nbgl_useCaseGetNbBarsInPage(nbElements, &content->content.barsList, elemIdx, hasNav);
            } else if (content->type == CHOICES_LIST) {
                nbElementsInPage = nbgl_useCaseGetNbChoicesInPage(nbElements, &content->content.choicesList, elemIdx, hasNav);
            } else {
                nbElementsInPage = ((nbMaxElementsPerContentType[content->type]) < (nbElements) ? (nbMaxElementsPerContentType[content->type]) : (nbElements));
            }
            elemIdx += nbElementsInPage;
            genericContextSetPageInfo(pageIdxStart + nbPages, nbElementsInPage, flag);
            nbElements -= nbElementsInPage;
            nbPages++;
        }
    return nbPages;
}

/* Function: getNbPagesForGenericContents */
static uint8_t getNbPagesForGenericContents(const nbgl_genericContents_t *genericContents, uint8_t pageIdxStart, bool isSkippable) {
    uint8_t nbPages = 0;
    nbgl_content_t content;
    const nbgl_content_t *p_content;
    for (int i = 0; i < genericContents->nbContents; i++) {
        p_content = getContentAtIdx(genericContents, i, &content);
        if (p_content == ((void *)0)) {
            return 0;
        }
        nbPages += getNbPagesForContent(p_content, pageIdxStart + nbPages, (i == (genericContents->nbContents - 1)), isSkippable);
    }
    return nbPages;
}

